CREATE OR REPLACE FUNCTION public.accept_booking_assignment(p_booking_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_uid uuid := auth.uid();
  v_row public.bookings%ROWTYPE;
  v_lat double precision;
  v_lng double precision;
  v_duration numeric;
  v_services text[];
  v_requested_category public.service_category;
  v_eligible boolean := false;
BEGIN
  IF v_uid IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'not_authenticated');
  END IF;

  SELECT * INTO v_row
  FROM public.bookings
  WHERE id = p_booking_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'not_found');
  END IF;

  IF v_row.customer_id = v_uid THEN
    RETURN jsonb_build_object('success', false, 'error', 'self_booking_not_allowed');
  END IF;

  IF lower(COALESCE(v_row.payment_status, '')) <> 'paid' THEN
    RETURN jsonb_build_object('success', false, 'error', 'payment_not_paid');
  END IF;

  IF v_row.cleaner_accepted_at IS NOT NULL OR v_row.assignment_phase = 'accepted' THEN
    IF v_row.cleaner_id = v_uid THEN
      RETURN jsonb_build_object('success', true, 'already_accepted', true);
    END IF;
    RETURN jsonb_build_object('success', false, 'error', 'already_taken');
  END IF;

  IF v_row.assignment_phase = 'exclusive' THEN
    v_eligible := v_row.direct_assigned_cleaner_id = v_uid OR v_row.cleaner_id = v_uid;
  ELSIF v_row.assignment_phase = 'broadcast' THEN
    IF v_row.cleaner_id IS NOT NULL AND v_row.cleaner_id <> v_uid THEN
      RETURN jsonb_build_object('success', false, 'error', 'already_taken');
    END IF;
    IF v_row.location_coordinates IS NULL THEN
      v_eligible := v_uid = v_row.direct_assigned_cleaner_id;
    ELSE
      v_lat := ST_Y(v_row.location_coordinates::geometry);
      v_lng := ST_X(v_row.location_coordinates::geometry);
      v_duration := COALESCE(v_row.duration_hours, v_row.duration_final, 2);
      v_services := COALESCE(v_row.extra_task_ids, ARRAY[]::text[]);
      v_requested_category := (
        SELECT st.category::public.service_category
        FROM public.service_types st
        WHERE st.id = v_row.service_id
      );
      SELECT EXISTS (
        SELECT 1
        FROM public.get_best_available_cleaners(
          v_row.scheduled_date::date,
          v_row.scheduled_time::time,
          v_duration::numeric,
          v_lat::double precision,
          v_lng::double precision,
          50000::integer,
          v_services::text[],
          p_booking_id::uuid,
          v_requested_category::public.service_category
        ) g
        WHERE g.cleaner_id = v_uid
      ) INTO v_eligible;
      IF NOT v_eligible AND v_row.direct_assigned_cleaner_id = v_uid THEN
        v_eligible := true;
      END IF;
    END IF;
  ELSE
    v_eligible := v_row.cleaner_id = v_uid
      AND v_row.status IN ('confirmed', 'scheduled');
  END IF;

  IF NOT v_eligible THEN
    RETURN jsonb_build_object('success', false, 'error', 'not_eligible');
  END IF;

  UPDATE public.bookings
  SET
    cleaner_id = v_uid,
    cleaner_accepted_at = now(),
    assignment_phase = 'accepted',
    assignment_hold_until = NULL,
    status = 'scheduled',
    updated_at = now(),
    last_updated = now()
  WHERE id = p_booking_id;

  INSERT INTO public.booking_timeline (booking_id, stage, changed_at, notes)
  VALUES (p_booking_id, 'scheduled', now(), 'Cleaner accepted assignment');

  IF v_row.customer_id IS NOT NULL THEN
    INSERT INTO public.notifications (user_id, type, title, message, data)
    VALUES (
      v_row.customer_id,
      'cleaner_accepted_assignment',
      'Cleaner confirmed',
      'Your cleaner accepted the job. We''ll keep you updated as your cleaning progresses.',
      jsonb_build_object('booking_id', p_booking_id, 'bookingId', p_booking_id, 'cleaner_id', v_uid)
    );
  END IF;

  RETURN jsonb_build_object('success', true, 'booking_id', p_booking_id, 'cleaner_id', v_uid);
END;
$function$


CREATE OR REPLACE FUNCTION public.accept_co_cleaner_invite(p_token uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_uid uuid := auth.uid();
  r public.co_cleaner_invitations%ROWTYPE;
BEGIN
  IF v_uid IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'not_authenticated');
  END IF;

  SELECT * INTO r
  FROM public.co_cleaner_invitations
  WHERE token = p_token
    AND status = 'pending'
    AND expires_at > now();

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'invalid_or_expired_invite');
  END IF;

  IF r.inviter_user_id = v_uid THEN
    RETURN jsonb_build_object('success', false, 'error', 'cannot_accept_own_invite');
  END IF;

  IF NOT public.is_co_cleaner_invitee_eligible(v_uid) THEN
    RETURN jsonb_build_object('success', false, 'error', 'co_cleaner_verification_required');
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM public.cleaner_data
    WHERE user_id = r.inviter_user_id AND verified IS TRUE
  ) THEN
    RETURN jsonb_build_object('success', false, 'error', 'inviter_not_verified');
  END IF;

  IF EXISTS (
    SELECT 1
    FROM public.co_cleaner_relationships AS rel
    WHERE rel.co_cleaner_id = v_uid
      AND rel.lead_cleaner_id <> r.inviter_user_id
  ) THEN
    RETURN jsonb_build_object('success', false, 'error', 'co_cleaner_already_on_team');
  END IF;

  INSERT INTO public.co_cleaner_relationships (lead_cleaner_id, co_cleaner_id)
  VALUES (r.inviter_user_id, v_uid)
  ON CONFLICT (lead_cleaner_id, co_cleaner_id) DO NOTHING;

  UPDATE public.co_cleaner_invitations
  SET
    status = 'accepted',
    accepted_user_id = v_uid,
    updated_at = now()
  WHERE id = r.id;

  RETURN jsonb_build_object('success', true, 'lead_cleaner_id', r.inviter_user_id);
END;
$function$


CREATE OR REPLACE FUNCTION public.accept_preferred_cleaner_invite(p_token uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_uid uuid := auth.uid();
  r public.preferred_cleaner_invitations%ROWTYPE;
BEGIN
  IF v_uid IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'not_authenticated');
  END IF;

  SELECT * INTO r
  FROM public.preferred_cleaner_invitations
  WHERE token = p_token
    AND status = 'pending'
    AND expires_at > now();

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'invalid_or_expired_invite');
  END IF;

  IF r.inviter_user_id = v_uid THEN
    RETURN jsonb_build_object('success', false, 'error', 'cannot_accept_own_invite');
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM public.cleaner_data
    WHERE user_id = v_uid AND verified IS TRUE
  ) THEN
    RETURN jsonb_build_object('success', false, 'error', 'preferred_invite_cleaner_not_verified');
  END IF;

  INSERT INTO public.preferred_cleaners (user_id, cleaner_id)
  VALUES (r.inviter_user_id, v_uid)
  ON CONFLICT (user_id, cleaner_id) DO NOTHING;

  UPDATE public.preferred_cleaner_invitations
  SET
    status = 'accepted',
    accepted_cleaner_id = v_uid,
    updated_at = now()
  WHERE id = r.id;

  RETURN jsonb_build_object(
    'success', true,
    'customer_user_id', r.inviter_user_id
  );
END;
$function$


CREATE OR REPLACE FUNCTION public.add_cleaner_record(p_user_id uuid, p_name text, p_bio text, p_avatar_url text, p_status text, p_verified boolean)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_clean_name      text := trim(coalesce(p_name, ''));
  v_first_name      text;
  v_last_name       text;
  v_status          public.cleaner_status := COALESCE(NULLIF(p_status, '')::public.cleaner_status, 'active'::public.cleaner_status);
  v_verified        boolean := COALESCE(p_verified, false);
  v_now             timestamptz := now();
  v_roles_inserted  int := 0;
BEGIN
  -- Confirm public.users mirror exists.
  PERFORM 1
  FROM public.users
  WHERE id = p_user_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'user_not_found' USING ERRCODE = 'P0002';
  END IF;

  v_first_name := NULLIF(split_part(v_clean_name, ' ', 1), '');

  v_last_name := NULLIF(
    regexp_replace(v_clean_name, '^\S+\s*', ''),
    ''
  );

  INSERT INTO public.profiles (
    id,
    user_id,
    firstname,
    lastname,
    avatar_url,
    bio,
    updated_at
  )
  VALUES (
    p_user_id,
    p_user_id,
    v_first_name,
    v_last_name,
    NULLIF(p_avatar_url, ''),
    NULLIF(p_bio, ''),
    v_now
  )
  ON CONFLICT (id) DO UPDATE SET
    firstname  = COALESCE(NULLIF(public.profiles.firstname, ''), EXCLUDED.firstname),
    lastname   = COALESCE(NULLIF(public.profiles.lastname, ''), EXCLUDED.lastname),
    avatar_url = COALESCE(NULLIF(public.profiles.avatar_url, ''), EXCLUDED.avatar_url),
    bio        = COALESCE(NULLIF(public.profiles.bio, ''), EXCLUDED.bio),
    updated_at = v_now;

  WITH inserted_roles AS (
    INSERT INTO public.user_roles (user_id, role_id)
    VALUES
      (p_user_id, 'cleaner'),
      (p_user_id, 'customer')
    ON CONFLICT (user_id, role_id) DO NOTHING
    RETURNING role_id
  )
  SELECT count(*) INTO v_roles_inserted
  FROM inserted_roles;

  INSERT INTO public.cleaner_data (
    user_id,
    bio,
    status,
    verified,
    skills,
    languages,
    service_areas,
    equipment_owned,
    updated_at
  )
  VALUES (
    p_user_id,
    NULLIF(p_bio, ''),
    v_status,
    v_verified,
    ARRAY[]::text[],
    ARRAY['English']::text[],
    ARRAY[]::text[],
    ARRAY[]::text[],
    v_now
  )
  ON CONFLICT (user_id) DO UPDATE SET
    bio        = COALESCE(NULLIF(EXCLUDED.bio, ''), public.cleaner_data.bio),
    status     = v_status,
    verified   = v_verified,
    updated_at = v_now;

  RETURN jsonb_build_object(
    'user_id', p_user_id,
    'status', v_status,
    'verified', v_verified,
    'roles_inserted', v_roles_inserted
  );
END;
$function$


CREATE OR REPLACE FUNCTION public.addauth(text)
 RETURNS boolean
 LANGUAGE plpgsql
AS $function$
DECLARE
	lockid alias for $1;
	okay boolean;
	myrec record;
BEGIN
	-- check to see if table exists
	--  if not, CREATE TEMP TABLE mylock (transid xid, lockcode text)
	okay := 'f';
	FOR myrec IN SELECT * FROM pg_class WHERE relname = 'temp_lock_have_table' LOOP
		okay := 't';
	END LOOP;
	IF (okay <> 't') THEN
		CREATE TEMP TABLE temp_lock_have_table (transid xid, lockcode text);
			-- this will only work from pgsql7.4 up
			-- ON COMMIT DELETE ROWS;
	END IF;

	--  INSERT INTO mylock VALUES ( $1)
--	EXECUTE 'INSERT INTO temp_lock_have_table VALUES ( '||
--		quote_literal(getTransactionID()) || ',' ||
--		quote_literal(lockid) ||')';

	INSERT INTO temp_lock_have_table VALUES (getTransactionID(), lockid);

	RETURN true::boolean;
END;
$function$


CREATE OR REPLACE FUNCTION public.addgeometrycolumn(catalog_name character varying, schema_name character varying, table_name character varying, column_name character varying, new_srid_in integer, new_type character varying, new_dim integer, use_typmod boolean DEFAULT true)
 RETURNS text
 LANGUAGE plpgsql
 STRICT
AS $function$
DECLARE
	rec RECORD;
	sr varchar;
	real_schema name;
	sql text;
	new_srid integer;

BEGIN

	-- Verify geometry type
	IF (postgis_type_name(new_type,new_dim) IS NULL )
	THEN
		RAISE EXCEPTION 'Invalid type name "%(%)" - valid ones are:
	POINT, MULTIPOINT,
	LINESTRING, MULTILINESTRING,
	POLYGON, MULTIPOLYGON,
	CIRCULARSTRING, COMPOUNDCURVE, MULTICURVE,
	CURVEPOLYGON, MULTISURFACE,
	GEOMETRY, GEOMETRYCOLLECTION,
	POINTM, MULTIPOINTM,
	LINESTRINGM, MULTILINESTRINGM,
	POLYGONM, MULTIPOLYGONM,
	CIRCULARSTRINGM, COMPOUNDCURVEM, MULTICURVEM
	CURVEPOLYGONM, MULTISURFACEM, TRIANGLE, TRIANGLEM,
	POLYHEDRALSURFACE, POLYHEDRALSURFACEM, TIN, TINM
	or GEOMETRYCOLLECTIONM', new_type, new_dim;
		RETURN 'fail';
	END IF;

	-- Verify dimension
	IF ( (new_dim >4) OR (new_dim <2) ) THEN
		RAISE EXCEPTION 'invalid dimension';
		RETURN 'fail';
	END IF;

	IF ( (new_type LIKE '%M') AND (new_dim!=3) ) THEN
		RAISE EXCEPTION 'TypeM needs 3 dimensions';
		RETURN 'fail';
	END IF;

	-- Verify SRID
	IF ( new_srid_in > 0 ) THEN
		IF new_srid_in > 998999 THEN
			RAISE EXCEPTION 'AddGeometryColumn() - SRID must be <= %', 998999;
		END IF;
		new_srid := new_srid_in;
		SELECT SRID INTO sr FROM spatial_ref_sys WHERE SRID = new_srid;
		IF NOT FOUND THEN
			RAISE EXCEPTION 'AddGeometryColumn() - invalid SRID';
			RETURN 'fail';
		END IF;
	ELSE
		new_srid := public.ST_SRID('POINT EMPTY'::public.geometry);
		IF ( new_srid_in != new_srid ) THEN
			RAISE NOTICE 'SRID value % converted to the officially unknown SRID value %', new_srid_in, new_srid;
		END IF;
	END IF;

	-- Verify schema
	IF ( schema_name IS NOT NULL AND schema_name != '' ) THEN
		sql := 'SELECT nspname FROM pg_namespace ' ||
			'WHERE text(nspname) = ' || quote_literal(schema_name) ||
			'LIMIT 1';
		RAISE DEBUG '%', sql;
		EXECUTE sql INTO real_schema;

		IF ( real_schema IS NULL ) THEN
			RAISE EXCEPTION 'Schema % is not a valid schemaname', quote_literal(schema_name);
			RETURN 'fail';
		END IF;
	END IF;

	IF ( real_schema IS NULL ) THEN
		RAISE DEBUG 'Detecting schema';
		sql := 'SELECT n.nspname AS schemaname ' ||
			'FROM pg_catalog.pg_class c ' ||
			  'JOIN pg_catalog.pg_namespace n ON n.oid = c.relnamespace ' ||
			'WHERE c.relkind = ' || quote_literal('r') ||
			' AND n.nspname NOT IN (' || quote_literal('pg_catalog') || ', ' || quote_literal('pg_toast') || ')' ||
			' AND pg_catalog.pg_table_is_visible(c.oid)' ||
			' AND c.relname = ' || quote_literal(table_name);
		RAISE DEBUG '%', sql;
		EXECUTE sql INTO real_schema;

		IF ( real_schema IS NULL ) THEN
			RAISE EXCEPTION 'Table % does not occur in the search_path', quote_literal(table_name);
			RETURN 'fail';
		END IF;
	END IF;

	-- Add geometry column to table
	IF use_typmod THEN
		 sql := 'ALTER TABLE ' ||
			quote_ident(real_schema) || '.' || quote_ident(table_name)
			|| ' ADD COLUMN ' || quote_ident(column_name) ||
			' geometry(' || public.postgis_type_name(new_type, new_dim) || ', ' || new_srid::text || ')';
		RAISE DEBUG '%', sql;
	ELSE
		sql := 'ALTER TABLE ' ||
			quote_ident(real_schema) || '.' || quote_ident(table_name)
			|| ' ADD COLUMN ' || quote_ident(column_name) ||
			' geometry ';
		RAISE DEBUG '%', sql;
	END IF;
	EXECUTE sql;

	IF NOT use_typmod THEN
		-- Add table CHECKs
		sql := 'ALTER TABLE ' ||
			quote_ident(real_schema) || '.' || quote_ident(table_name)
			|| ' ADD CONSTRAINT '
			|| quote_ident('enforce_srid_' || column_name)
			|| ' CHECK (st_srid(' || quote_ident(column_name) ||
			') = ' || new_srid::text || ')' ;
		RAISE DEBUG '%', sql;
		EXECUTE sql;

		sql := 'ALTER TABLE ' ||
			quote_ident(real_schema) || '.' || quote_ident(table_name)
			|| ' ADD CONSTRAINT '
			|| quote_ident('enforce_dims_' || column_name)
			|| ' CHECK (st_ndims(' || quote_ident(column_name) ||
			') = ' || new_dim::text || ')' ;
		RAISE DEBUG '%', sql;
		EXECUTE sql;

		IF ( NOT (new_type = 'GEOMETRY')) THEN
			sql := 'ALTER TABLE ' ||
				quote_ident(real_schema) || '.' || quote_ident(table_name) || ' ADD CONSTRAINT ' ||
				quote_ident('enforce_geotype_' || column_name) ||
				' CHECK (GeometryType(' ||
				quote_ident(column_name) || ')=' ||
				quote_literal(new_type) || ' OR (' ||
				quote_ident(column_name) || ') is null)';
			RAISE DEBUG '%', sql;
			EXECUTE sql;
		END IF;
	END IF;

	RETURN
		real_schema || '.' ||
		table_name || '.' || column_name ||
		' SRID:' || new_srid::text ||
		' TYPE:' || new_type ||
		' DIMS:' || new_dim::text || ' ';
END;
$function$


CREATE OR REPLACE FUNCTION public.addgeometrycolumn(schema_name character varying, table_name character varying, column_name character varying, new_srid integer, new_type character varying, new_dim integer, use_typmod boolean DEFAULT true)
 RETURNS text
 LANGUAGE plpgsql
 STABLE STRICT
AS $function$
DECLARE
	ret  text;
BEGIN
	SELECT public.AddGeometryColumn('',$1,$2,$3,$4,$5,$6,$7) into ret;
	RETURN ret;
END;
$function$


CREATE OR REPLACE FUNCTION public.addgeometrycolumn(table_name character varying, column_name character varying, new_srid integer, new_type character varying, new_dim integer, use_typmod boolean DEFAULT true)
 RETURNS text
 LANGUAGE plpgsql
 STRICT
AS $function$
DECLARE
	ret  text;
BEGIN
	SELECT public.AddGeometryColumn('','',$1,$2,$3,$4,$5, $6) into ret;
	RETURN ret;
END;
$function$


CREATE OR REPLACE FUNCTION public.admin_soft_delete_user(p_user_id uuid, p_reason text DEFAULT 'Deleted by admin'::text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_now timestamptz := now();
begin
  update public.users
  set
    status = 'inactive',
    email = 'deleted+' || p_user_id || '@tryinstaclean.local',
    phone = null,
    deleted_at = v_now,
    deleted_reason = p_reason,
    updated_at = v_now
  where id = p_user_id;

  if not found then
    raise exception 'user % not found', p_user_id;
  end if;

  -- Existing visibility helpers (lib/profile-visibility.ts) hide profiles
  -- once deleted_at / deactivated_at / deletion_status are set.
  update public.profiles
  set
    fullname = 'Deleted User',
    firstname = null,
    lastname = null,
    bio = null,
    address = null,
    avatar_url = null,
    deleted_at = v_now,
    deactivated_at = v_now,
    deletion_status = 'completed',
    updated_at = v_now
  where id = p_user_id;
end;
$function$


CREATE OR REPLACE FUNCTION public.apply_referral_code(p_code text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_user uuid := auth.uid();
  v_code text := upper(trim(coalesce(p_code, '')));
  v_referrer_id uuid;
  v_referrer_referred_by uuid;
  v_my_referred_by uuid;
  v_referrer_name text;
begin
  if v_user is null then
    return jsonb_build_object('success', false, 'error', 'not_authenticated');
  end if;

  if v_code = '' then
    return jsonb_build_object('success', false, 'error', 'invalid_code');
  end if;

  select referred_by into v_my_referred_by from users where id = v_user;
  if v_my_referred_by is not null then
    return jsonb_build_object('success', false, 'error', 'already_redeemed');
  end if;

  -- Referrals are for new users: anyone already active in the marketplace as
  -- a customer (any non-cancelled, non-pending booking) cannot redeem.
  if exists (
    select 1
    from bookings b
    where b.customer_id = v_user
      and b.status in ('confirmed', 'scheduled', 'en_route', 'arrived', 'in_progress', 'completed')
  ) then
    return jsonb_build_object('success', false, 'error', 'not_new_user');
  end if;

  select id, referred_by
    into v_referrer_id, v_referrer_referred_by
  from users
  where referral_code = v_code;

  if v_referrer_id is null then
    return jsonb_build_object('success', false, 'error', 'invalid_code');
  end if;

  if v_referrer_id = v_user then
    return jsonb_build_object('success', false, 'error', 'own_code');
  end if;

  if v_referrer_referred_by = v_user then
    return jsonb_build_object('success', false, 'error', 'circular_referral');
  end if;

  update users
    set referred_by = v_referrer_id,
        referred_at = now()
  where id = v_user and referred_by is null;

  if not found then
    return jsonb_build_object('success', false, 'error', 'already_redeemed');
  end if;

  select coalesce(nullif(trim(p.fullname), ''), nullif(trim(p.firstname), ''))
    into v_referrer_name
  from profiles p
  where p.id = v_referrer_id;

  return jsonb_build_object(
    'success', true,
    'referrer_name', v_referrer_name
  );
end;
$function$


CREATE OR REPLACE FUNCTION public.approve_and_complete_booking(p_booking_id uuid, p_rating integer, p_feedback text)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN
    -- 1. Verify the booking is actually ready for approval
    IF NOT EXISTS (SELECT 1 FROM public.bookings WHERE id = p_booking_id AND status = 'awaiting_approval') THEN
        RAISE EXCEPTION 'Booking is not in a state that can be approved.';
    END IF;

    -- 2. Update the booking to final completed status
    UPDATE public.bookings
    SET 
        status = 'completed',
        updated_at = now()
    WHERE id = p_booking_id;

    -- 3. Update cleaner metrics (rating)
    UPDATE public.cleaner_data
    SET 
        rating = (rating * completed_jobs + p_rating) / (completed_jobs + 1),
        completed_jobs = completed_jobs + 1
    WHERE user_id = (SELECT cleaner_id FROM public.bookings WHERE id = p_booking_id);

    -- 4. Log final note to timeline
    INSERT INTO public.booking_timeline (booking_id, stage, notes)
    VALUES (p_booking_id, 'completed', 'Customer approved: ' || p_feedback);
END;
$function$


CREATE OR REPLACE FUNCTION public.approve_cleaner_application(p_application_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_app                public.cleaner_applications%ROWTYPE;
  v_user_id            uuid;
  v_first_name         text;
  v_last_name          text;
  v_app_phone_e164     text;
  v_now                timestamptz := now();
  v_roles_inserted     int := 0;
  v_service_categories public.service_category[];
BEGIN
  SELECT * INTO v_app
  FROM public.cleaner_applications
  WHERE id = p_application_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'application_not_found' USING ERRCODE = 'P0001';
  END IF;

  v_app_phone_e164 := public.normalize_ghana_phone_to_e164(v_app.phone);

  v_user_id := v_app.user_id;

  IF v_user_id IS NULL AND NULLIF(trim(v_app.email), '') IS NOT NULL THEN
    SELECT id INTO v_user_id
    FROM public.users
    WHERE lower(email) = lower(trim(v_app.email))
    ORDER BY created_at ASC
    LIMIT 1;
  END IF;

  IF v_user_id IS NULL AND v_app_phone_e164 IS NOT NULL THEN
    SELECT id INTO v_user_id
    FROM public.users
    WHERE public.normalize_ghana_phone_to_e164(phone) = v_app_phone_e164
    ORDER BY created_at ASC
    LIMIT 1;
  END IF;

  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'user_not_found' USING ERRCODE = 'P0002';
  END IF;

  PERFORM 1
  FROM public.users
  WHERE id = v_user_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'user_not_found' USING ERRCODE = 'P0002';
  END IF;

  -- Offered categories from the application's service_type_ids. NULL when the
  -- application listed no services, so existing cleaner_data is not clobbered.
  SELECT array_agg(DISTINCT st.category)
  INTO v_service_categories
  FROM unnest(COALESCE(v_app.service_type_ids, '{}'::int[])) AS sid
  JOIN public.service_types st ON st.id = sid
  WHERE st.category IS NOT NULL;

  v_first_name := NULLIF(split_part(trim(coalesce(v_app.name, '')), ' ', 1), '');

  v_last_name := NULLIF(
    regexp_replace(trim(coalesce(v_app.name, '')), '^\S+\s*', ''),
    ''
  );

  INSERT INTO public.profiles (
    id,
    user_id,
    firstname,
    lastname,
    bio,
    updated_at
  )
  VALUES (
    v_user_id,
    v_user_id,
    v_first_name,
    v_last_name,
    NULLIF(v_app.bio, ''),
    v_now
  )
  ON CONFLICT (id) DO UPDATE SET
    firstname  = COALESCE(NULLIF(public.profiles.firstname, ''), EXCLUDED.firstname),
    lastname   = COALESCE(NULLIF(public.profiles.lastname, ''), EXCLUDED.lastname),
    bio        = COALESCE(NULLIF(public.profiles.bio, ''), EXCLUDED.bio),
    updated_at = v_now;

  WITH inserted_roles AS (
    INSERT INTO public.user_roles (user_id, role_id)
    VALUES
      (v_user_id, 'cleaner'),
      (v_user_id, 'customer')
    ON CONFLICT (user_id, role_id) DO NOTHING
    RETURNING role_id
  )
  SELECT count(*) INTO v_roles_inserted
  FROM inserted_roles;

  INSERT INTO public.cleaner_data (
    user_id,
    bio,
    skills,
    certifications,
    service_areas,
    service_categories,
    hourly_rate,
    status,
    verified,
    updated_at
  )
  VALUES (
    v_user_id,
    NULLIF(v_app.bio, ''),
    v_app.skills,
    v_app.certifications,
    v_app.service_areas,
    v_service_categories,
    v_app.hourly_rate,
    'active',
    true,
    v_now
  )
  ON CONFLICT (user_id) DO UPDATE SET
    bio                = COALESCE(NULLIF(EXCLUDED.bio, ''), public.cleaner_data.bio),
    skills             = COALESCE(EXCLUDED.skills, public.cleaner_data.skills),
    certifications     = COALESCE(EXCLUDED.certifications, public.cleaner_data.certifications),
    service_areas      = COALESCE(EXCLUDED.service_areas, public.cleaner_data.service_areas),
    service_categories = COALESCE(EXCLUDED.service_categories, public.cleaner_data.service_categories),
    hourly_rate        = COALESCE(EXCLUDED.hourly_rate, public.cleaner_data.hourly_rate),
    status = CASE
      WHEN public.cleaner_data.status = 'suspended'
      THEN public.cleaner_data.status
      ELSE 'active'
    END,
    verified   = true,
    updated_at = v_now;

  UPDATE public.cleaner_applications
  SET status     = 'approved',
      user_id    = v_user_id,
      updated_at = v_now
  WHERE id = p_application_id;

  RETURN jsonb_build_object(
    'user_id', v_user_id,
    'application_id', p_application_id,
    'approved_user_id', v_user_id,
    'status', 'approved',
    'roles_inserted', v_roles_inserted
  );
END;
$function$


CREATE OR REPLACE FUNCTION public.assign_cleaner_after_payment(p_booking_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_uid uuid := auth.uid();
  v_row public.bookings%ROWTYPE;
  v_lat double precision;
  v_lng double precision;
  v_duration numeric;
  v_service_tz text;
  v_booking_range tstzrange;
  v_candidate uuid;
  v_assigned uuid;
  v_payment text;
  v_services text[];
BEGIN
  IF v_uid IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'not_authenticated');
  END IF;

  IF p_booking_id IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'missing_booking_id');
  END IF;

  SELECT * INTO v_row
  FROM public.bookings
  WHERE id = p_booking_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'not_found');
  END IF;

  IF v_row.customer_id IS DISTINCT FROM v_uid THEN
    RETURN jsonb_build_object('success', false, 'error', 'not_authorized');
  END IF;

  v_payment := lower(trim(coalesce(v_row.payment_status, '')));
  IF v_payment <> 'paid' THEN
    RETURN jsonb_build_object('success', false, 'error', 'payment_not_paid');
  END IF;

  IF v_row.cleaner_id IS NOT NULL THEN
    RETURN jsonb_build_object(
      'success', true,
      'already_assigned', true,
      'cleaner_id', v_row.cleaner_id,
      'booking_id', p_booking_id
    );
  END IF;

  IF v_row.location_coordinates IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'missing_location');
  END IF;

  IF v_row.scheduled_date IS NULL OR v_row.scheduled_time IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'missing_schedule');
  END IF;

  v_lat := ST_Y(v_row.location_coordinates::geometry);
  v_lng := ST_X(v_row.location_coordinates::geometry);
  v_duration := COALESCE(v_row.duration_hours, v_row.duration_final, 2);
  v_services := COALESCE(v_row.extra_task_ids, ARRAY[]::text[]);
  v_service_tz := COALESCE(NULLIF(trim(v_row.timezone_name), ''), 'Africa/Accra');

  v_booking_range := COALESCE(
    v_row.booking_period::tstzrange,
    tstzrange(
      (v_row.scheduled_date + v_row.scheduled_time) AT TIME ZONE v_service_tz,
      (
        v_row.scheduled_date
        + v_row.scheduled_time
        + (v_duration || ' hours')::interval
      ) AT TIME ZONE v_service_tz,
      '[)'
    )
  );

  v_assigned := NULL;

  FOR v_candidate IN
    SELECT g.cleaner_id
    FROM public.get_best_available_cleaners(
      v_row.scheduled_date,
      v_row.scheduled_time,
      v_duration,
      v_lat,
      v_lng,
      50000,
      v_services,
      p_booking_id
    ) g
    WHERE g.cleaner_id IS DISTINCT FROM v_row.customer_id
    ORDER BY g.final_score DESC NULLS LAST, g.distance_meters ASC
  LOOP
    UPDATE public.bookings b
    SET
      cleaner_id = v_candidate,
      updated_at = now()
    WHERE b.id = p_booking_id
      AND b.cleaner_id IS NULL
      AND NOT EXISTS (
        SELECT 1
        FROM public.bookings other
        WHERE other.cleaner_id = v_candidate
          AND other.id <> p_booking_id
          AND other.status IN ('confirmed', 'scheduled', 'en_route', 'arrived', 'in_progress')
          AND COALESCE(
            other.booking_period::tstzrange,
            tstzrange(
              (other.scheduled_date + other.scheduled_time) AT TIME ZONE COALESCE(NULLIF(trim(other.timezone_name), ''), 'Africa/Accra'),
              (
                other.scheduled_date
                + other.scheduled_time
                + (COALESCE(other.duration_hours, other.duration_final, 2) || ' hours')::interval
              ) AT TIME ZONE COALESCE(NULLIF(trim(other.timezone_name), ''), 'Africa/Accra'),
              '[)'
            )
          ) && v_booking_range
      );

    IF FOUND THEN
      v_assigned := v_candidate;
      EXIT;
    END IF;
  END LOOP;

  IF v_assigned IS NULL THEN
    FOR v_candidate IN
      SELECT s.cleaner_id
      FROM public.search_available_cleaners(
        v_lat,
        v_lng,
        v_row.scheduled_date,
        v_row.scheduled_time,
        v_duration,
        v_services,
        50000,
        p_booking_id
      ) s
      WHERE s.cleaner_id IS DISTINCT FROM v_row.customer_id
    LOOP
      UPDATE public.bookings b
      SET
        cleaner_id = v_candidate,
        updated_at = now()
      WHERE b.id = p_booking_id
        AND b.cleaner_id IS NULL
        AND NOT EXISTS (
          SELECT 1
          FROM public.bookings other
          WHERE other.cleaner_id = v_candidate
            AND other.id <> p_booking_id
            AND other.status IN ('confirmed', 'scheduled', 'en_route', 'arrived', 'in_progress')
            AND COALESCE(
              other.booking_period::tstzrange,
              tstzrange(
                (other.scheduled_date + other.scheduled_time) AT TIME ZONE COALESCE(NULLIF(trim(other.timezone_name), ''), 'Africa/Accra'),
                (
                  other.scheduled_date
                  + other.scheduled_time
                  + (COALESCE(other.duration_hours, other.duration_final, 2) || ' hours')::interval
                ) AT TIME ZONE COALESCE(NULLIF(trim(other.timezone_name), ''), 'Africa/Accra'),
                '[)'
              )
            ) && v_booking_range
        );

      IF FOUND THEN
        v_assigned := v_candidate;
        EXIT;
      END IF;
    END LOOP;
  END IF;

  IF v_assigned IS NULL THEN
    SELECT cleaner_id INTO v_assigned
    FROM public.bookings
    WHERE id = p_booking_id;

    IF v_assigned IS NOT NULL THEN
      RETURN jsonb_build_object(
        'success', true,
        'already_assigned', true,
        'cleaner_id', v_assigned,
        'booking_id', p_booking_id
      );
    END IF;

    RETURN jsonb_build_object('success', false, 'error', 'no_cleaners_available');
  END IF;

  INSERT INTO public.booking_timeline (booking_id, stage, changed_at, notes)
  VALUES (p_booking_id, v_row.status, now(), 'Cleaner assigned after payment');

  IF v_row.customer_id IS NOT NULL THEN
    INSERT INTO public.notifications (user_id, type, title, message, data)
    VALUES (
      v_row.customer_id,
      'cleaner_assigned',
      'Cleaner assigned',
      'A cleaner has been assigned to your booking.',
      jsonb_build_object(
        'booking_id', p_booking_id,
        'bookingId', p_booking_id,
        'cleaner_id', v_assigned
      )
    );
  END IF;

  RETURN jsonb_build_object(
    'success', true,
    'cleaner_id', v_assigned,
    'booking_id', p_booking_id
  );
END;
$function$


CREATE OR REPLACE FUNCTION public.assign_user_role(target_user_id uuid, target_role_id text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
  INSERT INTO public.user_roles (user_id, role_id)
  VALUES (target_user_id, target_role_id)
  ON CONFLICT (user_id, role_id) DO NOTHING;
END;
$function$


CREATE OR REPLACE FUNCTION public.assign_user_role(target_user_id uuid, target_role_id text, is_verified boolean DEFAULT false)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
  -- 1. Assign the role to the user
  INSERT INTO public.user_roles (user_id, role_id)
  VALUES (target_user_id, target_role_id)
  ON CONFLICT (user_id, role_id) DO NOTHING;

  -- 2. If the role is 'cleaner', sync the verified status in cleaner_data
  IF target_role_id = 'cleaner' THEN
    INSERT INTO public.cleaner_data (user_id, verified, status)
    VALUES (target_user_id, is_verified, 'active')
    ON CONFLICT (user_id) 
    DO UPDATE SET 
      verified = EXCLUDED.verified,
      status = 'active';
  END IF;
END;
$function$


CREATE OR REPLACE FUNCTION public.backfill_cleaner_application_approval(p_user_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_app_id     uuid;
  v_user_email text;
  v_user_phone text;
BEGIN
  SELECT email, public.normalize_ghana_phone_to_e164(phone)
  INTO v_user_email, v_user_phone
  FROM public.users
  WHERE id = p_user_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'user_not_found' USING ERRCODE = 'P0002';
  END IF;

  SELECT id INTO v_app_id
  FROM public.cleaner_applications
  WHERE COALESCE(status, 'pending') NOT IN ('rejected')
    AND (
      user_id = p_user_id
      OR (
        v_user_email IS NOT NULL
        AND NULLIF(trim(email), '') IS NOT NULL
        AND lower(email) = lower(v_user_email)
      )
      OR (
        v_user_phone IS NOT NULL
        AND public.normalize_ghana_phone_to_e164(phone) = v_user_phone
      )
    )
  ORDER BY
    CASE
      WHEN COALESCE(status, 'pending') = 'approved' THEN 2
      ELSE 1
    END,
    created_at DESC
  LIMIT 1;

  IF v_app_id IS NULL THEN
    RAISE EXCEPTION 'application_not_found' USING ERRCODE = 'P0001';
  END IF;

  RETURN public.approve_cleaner_application(v_app_id);
END;
$function$


CREATE OR REPLACE FUNCTION public.booking_broadcast_grace_ends_at(p_scheduled_at_utc timestamp with time zone, p_duration_hours numeric, p_duration_final numeric)
 RETURNS timestamp with time zone
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT p_scheduled_at_utc
    + (COALESCE(p_duration_hours, p_duration_final, 2) || ' hours')::interval
    + interval '3 hours';
$function$


CREATE OR REPLACE FUNCTION public.booking_cover_major_from_booking(p_cover_amount numeric)
 RETURNS numeric
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
DECLARE
  v_raw numeric := COALESCE(p_cover_amount, 0);
BEGIN
  IF v_raw <= 0 THEN
    RETURN 0;
  END IF;
  IF v_raw >= 100 THEN
    RETURN ROUND(GREATEST(0, v_raw / 100.0), 2);
  END IF;
  RETURN ROUND(GREATEST(0, v_raw), 2);
END;
$function$


CREATE OR REPLACE FUNCTION public.bookings_guard_payment_status()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF OLD.payment_status IS NOT DISTINCT FROM NEW.payment_status THEN
    RETURN NEW;
  END IF;

  IF NEW.payment_status IN ('paid', 'refunded', 'partially_refunded')
     AND auth.role() IN ('authenticated', 'anon') THEN
    RAISE EXCEPTION
      'payment_status % cannot be set by client',
      NEW.payment_status
      USING ERRCODE = '42501';
  END IF;

  RETURN NEW;
END;
$function$


CREATE OR REPLACE FUNCTION public.bookings_set_duration()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  r record;
BEGIN
  SELECT *
  INTO r
  FROM public.calculate_booking_duration(
    NEW.home_size,
    COALESCE(NEW.extra_task_ids, '{}'::text[]),
    COALESCE(NEW.duration_adjustment, 0),
    12
  );

  IF r.computed_hours IS NULL OR r.final_hours IS NULL THEN
    RAISE EXCEPTION
      'Booking failed: duration engine returned NULL (computed_hours=%, final_hours=%).',
      r.computed_hours, r.final_hours;
  END IF;

  NEW.duration_computed := r.computed_hours;
  NEW.duration_final := r.final_hours;

  -- Keep user-provided duration_hours if present; otherwise fill it
  NEW.duration_hours := COALESCE(NEW.duration_hours, r.final_hours);

  IF NEW.duration_final <= 0 THEN
    RAISE EXCEPTION
      'Booking failed: final duration must be > 0 (final_hours=%).',
      NEW.duration_final;
  END IF;

  RETURN NEW;
END;
$function$


