CREATE OR REPLACE FUNCTION public.claim_job(p_job_id uuid, p_cleaner_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_job jobs%ROWTYPE;
  v_offer_exists boolean;
BEGIN
  IF auth.uid() IS DISTINCT FROM p_cleaner_id THEN
    RETURN jsonb_build_object('success', false, 'error', 'unauthorized');
  END IF;

  SELECT * INTO v_job FROM jobs WHERE id = p_job_id FOR UPDATE;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'job_not_found');
  END IF;

  IF v_job.status NOT IN ('pending', 'offered') OR v_job.claimed_by IS NOT NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'job_not_available');
  END IF;

  IF v_job.offer_expires_at IS NOT NULL AND v_job.offer_expires_at < now() THEN
    RETURN jsonb_build_object('success', false, 'error', 'offer_expired');
  END IF;

  SELECT EXISTS (
    SELECT 1 FROM job_offers
    WHERE job_id = p_job_id AND cleaner_id = p_cleaner_id AND status = 'sent'
  ) INTO v_offer_exists;

  IF NOT v_offer_exists THEN
    RETURN jsonb_build_object('success', false, 'error', 'no_offer');
  END IF;

  UPDATE jobs
  SET status = 'claimed', claimed_by = p_cleaner_id, claimed_at = now()
  WHERE id = p_job_id;

  UPDATE job_offers
  SET status = 'accepted', responded_at = now()
  WHERE job_id = p_job_id AND cleaner_id = p_cleaner_id;

  UPDATE job_offers
  SET status = 'expired'
  WHERE job_id = p_job_id AND cleaner_id <> p_cleaner_id;

  RETURN jsonb_build_object(
    'success', true,
    'job', to_jsonb((SELECT j FROM jobs j WHERE j.id = p_job_id))
  );
END;
$function$


CREATE OR REPLACE FUNCTION public.cleaner_earnings_subunit_from_booking(p_final_amount_minor integer, p_total_price numeric, p_platform_fee numeric, p_booking_cover boolean, p_booking_cover_amount numeric, p_core_amount_minor integer)
 RETURNS integer
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
DECLARE
  v_final_minor integer;
  v_final_major numeric;
  v_platform numeric;
  v_cover numeric;
  v_earnings_major numeric;
BEGIN
  v_final_minor := COALESCE(
    NULLIF(p_final_amount_minor, 0),
    NULLIF(FLOOR(COALESCE(p_total_price, 0))::integer, 0)
  );

  IF v_final_minor IS NULL OR v_final_minor <= 0 THEN
    RETURN 0;
  END IF;

  v_final_major := v_final_minor / 100.0;
  v_platform := public.platform_fee_major_from_booking(p_platform_fee, p_core_amount_minor);
  v_cover := public.resolve_booking_cover_major_for_cleaner_earnings(
    p_booking_cover,
    p_booking_cover_amount,
    p_core_amount_minor,
    p_platform_fee
  );
  v_earnings_major := ROUND(GREATEST(0, v_final_major - v_platform - v_cover), 2);

  RETURN GREATEST(0, (v_earnings_major * 100)::integer);
END;
$function$


CREATE OR REPLACE FUNCTION public.cleaner_team_branding_for(p_cleaner_id uuid)
 RETURNS TABLE(company_name text, team_role text, team_size integer)
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
BEGIN
  RETURN QUERY
  SELECT
    ct.company_name,
    'lead'::text,
    public.cleaner_team_co_count(p_cleaner_id)
  FROM public.cleaner_teams ct
  WHERE ct.lead_cleaner_id = p_cleaner_id
    AND NULLIF(BTRIM(ct.company_name), '') IS NOT NULL
  LIMIT 1;

  IF FOUND THEN
    RETURN;
  END IF;

  RETURN QUERY
  SELECT
    ct.company_name,
    'member'::text,
    public.cleaner_team_co_count(r.lead_cleaner_id)
  FROM public.co_cleaner_relationships r
  JOIN public.cleaner_teams ct ON ct.lead_cleaner_id = r.lead_cleaner_id
  WHERE r.co_cleaner_id = p_cleaner_id
    AND NULLIF(BTRIM(ct.company_name), '') IS NOT NULL
  LIMIT 1;
END;
$function$


