CREATE OR REPLACE FUNCTION public.count_unread_messages_for_user(p_user_id uuid)
 RETURNS integer
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT count(*)::integer
  FROM public.messages m
  JOIN public.conversations c ON c.id = m.conversation_id
  WHERE m.read_at IS NULL
    AND m.sender_id IS DISTINCT FROM p_user_id
    AND (c.customer_id = p_user_id OR c.cleaner_id = p_user_id);
$function$


CREATE OR REPLACE FUNCTION public.create_co_cleaner_invite(p_invitee_email text DEFAULT NULL::text, p_invitee_phone_e164 text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_uid uuid := auth.uid();
  v_token uuid := gen_random_uuid();
  v_expires timestamptz := now() + interval '30 days';
  v_id uuid;
  v_email text := NULLIF(lower(trim(COALESCE(p_invitee_email, ''))), '');
  v_phone text := NULLIF(trim(COALESCE(p_invitee_phone_e164, '')), '');
BEGIN
  IF v_uid IS NULL THEN
    RAISE EXCEPTION 'not_authenticated';
  END IF;
  IF NOT EXISTS (
    SELECT 1 FROM public.cleaner_data
    WHERE user_id = v_uid AND verified IS TRUE
  ) THEN
    RAISE EXCEPTION 'only_verified_cleaners_can_invite';
  END IF;

  INSERT INTO public.co_cleaner_invitations (
    inviter_user_id, token, invitee_email, invitee_phone_e164, expires_at
  )
  VALUES (v_uid, v_token, v_email, v_phone, v_expires)
  RETURNING id INTO v_id;

  RETURN jsonb_build_object(
    'success', true,
    'token', v_token,
    'invite_id', v_id,
    'expires_at', v_expires
  );
END;
$function$


