CREATE OR REPLACE FUNCTION public.escalate_unassigned_paid_bookings_past_grace()
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  r public.bookings%ROWTYPE;
  v_escalated integer := 0;
BEGIN
  FOR r IN
    SELECT *
    FROM public.bookings
    WHERE cleaner_id IS NULL
      AND cleaner_accepted_at IS NULL
      AND assignment_escalated_at IS NULL
      AND lower(COALESCE(payment_status, '')) = 'paid'
      AND status IN ('pending', 'confirmed', 'scheduled')
      AND scheduled_at_utc IS NOT NULL
      AND public.booking_broadcast_grace_ends_at(
        scheduled_at_utc, duration_hours, duration_final
      ) <= now()
      AND NOT (
        assignment_phase = 'exclusive'
        AND assignment_hold_until IS NOT NULL
        AND assignment_hold_until > now()
      )
      AND (
        assignment_phase IS NULL
        OR assignment_phase = 'broadcast'
      )
    ORDER BY scheduled_at_utc ASC
    FOR UPDATE SKIP LOCKED
  LOOP
    UPDATE public.bookings
    SET
      assignment_escalated_at = now(),
      updated_at = now(),
      last_updated = now()
    WHERE id = r.id;

    v_escalated := v_escalated + 1;

    IF r.customer_id IS NOT NULL
       AND NOT EXISTS (
         SELECT 1
         FROM public.notifications n
         WHERE n.user_id = r.customer_id
           AND n.type = 'unassigned_booking_escalated'
           AND n.data->>'booking_id' = r.id::text
       )
    THEN
      INSERT INTO public.notifications (user_id, type, title, message, data)
      VALUES (
        r.customer_id,
        'unassigned_booking_escalated',
        'We couldn''t assign a cleaner',
        'We couldn''t find a cleaner for your booking in time. Please reschedule or contact support for help.',
        jsonb_build_object(
          'booking_id', r.id,
          'bookingId', r.id,
          'assignment_phase', r.assignment_phase,
          'source', 'unassigned_paid_booking_escalation'
        )
      );
    END IF;
  END LOOP;

  RETURN jsonb_build_object(
    'ok', true,
    'escalated_count', v_escalated
  );
END;
$function$


CREATE OR REPLACE FUNCTION public.expire_stale_pending_bookings()
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  affected integer;
  v_now timestamptz := now();
BEGIN
  UPDATE public.bookings
  SET
    status = 'cancelled'::booking_status,
    updated_at = v_now
  WHERE status = 'pending'::booking_status
    AND payment_status = 'pending'
    AND subscription_id IS NULL
    AND created_at < (v_now - interval '48 hours')
    AND updated_at < (v_now - interval '48 hours');

  GET DIAGNOSTICS affected = ROW_COUNT;
  RETURN affected;
END;
$function$


CREATE OR REPLACE FUNCTION public.fetch_cleaner_earnings(p_user_id uuid, p_start_date timestamp with time zone, p_end_date timestamp with time zone)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_total_deduction_rate numeric;
    v_fixed_deductions numeric;
    v_in_transit numeric;
    v_estimated numeric;
    v_total numeric;
BEGIN
    -- 1. Calculate the sum of all active percentage-based and fixed rules
    SELECT 
        COALESCE(SUM(rate_percentage), 0) / 100, 
        COALESCE(SUM(fixed_amount), 0)
    INTO v_total_deduction_rate, v_fixed_deductions
    FROM public.deduction_rules 
    WHERE is_active = true AND end_date IS NULL;

    -- 2. In Transit: Gross amount minus dynamic deductions
    -- Money from jobs PAID but not yet COMPLETED
    SELECT COALESCE(
        SUM(total_price - (total_price * v_total_deduction_rate) - v_fixed_deductions), 
        0
    ) INTO v_in_transit 
    FROM public.bookings 
    WHERE cleaner_id = p_user_id 
    AND payment_status = 'paid' 
    AND status != 'completed';

    -- 3. Estimated Payout: Current actual balance in the wallet
    SELECT COALESCE(balance_subunit, 0) INTO v_estimated 
    FROM public.wallets 
    WHERE user_id = p_user_id;

    -- 4. Total Earnings: Sum of all completed credit transactions in date range
    SELECT COALESCE(SUM(amount_subunit), 0) INTO v_total 
    FROM public.wallet_transactions 
    WHERE wallet_id = (SELECT id FROM wallets WHERE user_id = p_user_id)
    AND type = 'credit'
    AND created_at BETWEEN p_start_date AND p_end_date;

    RETURN json_build_object(
        'inTransit', ROUND(v_in_transit),
        'estimatedPayout', v_estimated,
        'total', v_total
    );
END;
$function$


CREATE OR REPLACE FUNCTION public.find_srid(character varying, character varying, character varying)
 RETURNS integer
 LANGUAGE plpgsql
 STABLE PARALLEL SAFE STRICT
AS $function$
DECLARE
	schem varchar =  $1;
	tabl varchar = $2;
	sr int4;
BEGIN
-- if the table contains a . and the schema is empty
-- split the table into a schema and a table
-- otherwise drop through to default behavior
	IF ( schem = '' and strpos(tabl,'.') > 0 ) THEN
	 schem = substr(tabl,1,strpos(tabl,'.')-1);
	 tabl = substr(tabl,length(schem)+2);
	END IF;

	select SRID into sr from public.geometry_columns where (f_table_schema = schem or schem = '') and f_table_name = tabl and f_geometry_column = $3;
	IF NOT FOUND THEN
	   RAISE EXCEPTION 'find_srid() - could not find the corresponding SRID - is the geometry registered in the GEOMETRY_COLUMNS table?  Is there an uppercase/lowercase mismatch?';
	END IF;
	return sr;
END;
$function$


