CREATE OR REPLACE FUNCTION public.fn_begin_cleaner_withdrawal(p_cleaner_id uuid, p_amount_subunit integer, p_withdrawal_id uuid, p_recipient_code text DEFAULT NULL::text, p_payout_method_id uuid DEFAULT NULL::uuid)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_wallet_id uuid;
  v_balance integer;
  v_min_subunit constant integer := 5000; -- GHS 50
BEGIN
  IF p_cleaner_id IS NULL OR p_withdrawal_id IS NULL THEN
    RAISE EXCEPTION 'missing_cleaner_or_withdrawal_id';
  END IF;

  IF p_amount_subunit IS NULL OR p_amount_subunit < v_min_subunit THEN
    RAISE EXCEPTION 'below_minimum_withdrawal';
  END IF;

  IF EXISTS (
    SELECT 1
    FROM public.withdrawal_requests wr
    WHERE wr.id = p_withdrawal_id
      AND wr.cleaner_id = p_cleaner_id
      AND wr.amount_subunit = p_amount_subunit
  ) THEN
    RETURN p_withdrawal_id;
  END IF;

  IF EXISTS (
    SELECT 1 FROM public.withdrawal_requests wr
    WHERE wr.id = p_withdrawal_id
  ) THEN
    RAISE EXCEPTION 'withdrawal_id_conflict';
  END IF;

  SELECT w.id, COALESCE(w.balance_subunit, 0)
  INTO v_wallet_id, v_balance
  FROM public.wallets w
  WHERE w.user_id = p_cleaner_id
  FOR UPDATE;

  IF v_wallet_id IS NULL THEN
    RAISE EXCEPTION 'wallet_not_found';
  END IF;

  IF v_balance < p_amount_subunit THEN
    RAISE EXCEPTION 'insufficient_balance';
  END IF;

  UPDATE public.wallets
  SET
    balance_subunit = v_balance - p_amount_subunit,
    updated_at = NOW()
  WHERE id = v_wallet_id;

  INSERT INTO public.withdrawal_requests (
    id,
    cleaner_id,
    wallet_id,
    amount_subunit,
    status,
    paystack_reference,
    bank_details,
    created_at,
    updated_at
  ) VALUES (
    p_withdrawal_id,
    p_cleaner_id,
    v_wallet_id,
    p_amount_subunit,
    'processing',
    p_withdrawal_id::text,
    jsonb_build_object(
      'recipient_code', p_recipient_code,
      'payout_method_id', p_payout_method_id
    ),
    NOW(),
    NOW()
  );

  INSERT INTO public.wallet_transactions (
    wallet_id,
    amount_subunit,
    type,
    description,
    withdrawal_request_id
  ) VALUES (
    v_wallet_id,
    p_amount_subunit,
    'debit',
    'Withdrawal pending',
    p_withdrawal_id
  );

  RETURN p_withdrawal_id;
END;
$function$


CREATE OR REPLACE FUNCTION public.fn_create_wallet_for_new_cleaner()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    INSERT INTO public.wallets (user_id, balance_subunit, currency)
    VALUES (NEW.user_id, 0, 'GHS')
    ON CONFLICT (user_id) DO NOTHING;

    RETURN NEW;
END;
$function$


CREATE OR REPLACE FUNCTION public.fn_finalize_withdrawal(p_transfer_reference text, p_status withdrawal_status, p_error_msg text DEFAULT NULL::text)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_request_record RECORD;
BEGIN
    -- 1. Find the pending request
    SELECT * INTO v_request_record 
    FROM public.withdrawal_requests 
    WHERE id = p_transfer_reference::UUID -- We used our DB ID as the reference
    FOR UPDATE; -- Lock the row for safety

    IF v_request_record IS NULL THEN
        RAISE EXCEPTION 'Withdrawal request not found';
    END IF;

    -- 2. If Success: Update Request, Debit Wallet, Log Transaction
    IF p_status = 'success' THEN
        
        -- Update the request status
        UPDATE public.withdrawal_requests 
        SET status = 'success', updated_at = NOW() 
        WHERE id = v_request_record.id;

        -- Debit the actual wallet
        UPDATE public.wallets 
        SET balance_subunit = balance_subunit - v_request_record.amount_subunit,
            updated_at = NOW()
        WHERE id = v_request_record.wallet_id;

        -- Create the audit trail (The Debit)
        INSERT INTO public.wallet_transactions (
            wallet_id, amount_subunit, type, description
        ) VALUES (
            v_request_record.wallet_id, 
            v_request_record.amount_subunit, 
            'debit', 
            'Bank Transfer Payout (Ref: ' || v_request_record.paystack_transfer_code || ')'
        );

    -- 3. If Failed: Just update the request status so they can try again
    ELSIF p_status = 'failed' THEN
        UPDATE public.withdrawal_requests 
        SET status = 'failed', error_message = p_error_msg, updated_at = NOW() 
        WHERE id = v_request_record.id;
    END IF;

END;
$function$


CREATE OR REPLACE FUNCTION public.fn_finalize_withdrawal(p_transfer_reference text, p_status withdrawal_status, p_error_msg text DEFAULT NULL::text, p_paystack_transfer_code text DEFAULT NULL::text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_request public.withdrawal_requests%ROWTYPE;
  v_ref text := NULLIF(trim(p_transfer_reference), '');
BEGIN
  IF v_ref IS NULL THEN
    RAISE EXCEPTION 'missing_transfer_reference';
  END IF;

  SELECT * INTO v_request
  FROM public.withdrawal_requests
  WHERE paystack_reference = v_ref
  FOR UPDATE;

  IF NOT FOUND AND v_ref ~ '^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$' THEN
    SELECT * INTO v_request
    FROM public.withdrawal_requests
    WHERE id = v_ref::uuid
    FOR UPDATE;
  END IF;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Withdrawal request not found';
  END IF;

  -- Terminal-state safety (webhook order chaos).
  -- Allowed: processing/pending -> success | failed/reversed (refund)
  --          success -> reversed (refund)
  --          same terminal status -> no-op
  IF v_request.status = p_status THEN
    RETURN;
  END IF;

  IF v_request.status IN ('failed', 'reversed') THEN
    RETURN;
  END IF;

  IF v_request.status = 'success' AND p_status <> 'reversed' THEN
    RETURN;
  END IF;

  IF p_status = 'success' THEN
    UPDATE public.withdrawal_requests
    SET
      status = 'success',
      paystack_transfer_code = COALESCE(p_paystack_transfer_code, paystack_transfer_code),
      error_message = NULL,
      updated_at = NOW()
    WHERE id = v_request.id;

    UPDATE public.wallet_transactions
    SET description = 'Withdrawal completed (Ref: ' || COALESCE(
      p_paystack_transfer_code,
      v_request.paystack_transfer_code,
      v_ref
    ) || ')'
    WHERE withdrawal_request_id = v_request.id
      AND type = 'debit';

    RETURN;
  END IF;

  IF p_status IN ('failed', 'reversed') THEN
    IF v_request.status IN ('processing', 'pending') THEN
      UPDATE public.wallets
      SET
        balance_subunit = COALESCE(balance_subunit, 0) + v_request.amount_subunit,
        updated_at = NOW()
      WHERE id = v_request.wallet_id;

      INSERT INTO public.wallet_transactions (
        wallet_id,
        amount_subunit,
        type,
        description,
        withdrawal_request_id
      ) VALUES (
        v_request.wallet_id,
        v_request.amount_subunit,
        'credit',
        CASE
          WHEN p_status = 'reversed' THEN 'Withdrawal reversed — refunded'
          ELSE 'Withdrawal failed — refunded'
        END,
        v_request.id
      );
    ELSIF v_request.status = 'success' AND p_status = 'reversed' THEN
      UPDATE public.wallets
      SET
        balance_subunit = COALESCE(balance_subunit, 0) + v_request.amount_subunit,
        updated_at = NOW()
      WHERE id = v_request.wallet_id;

      INSERT INTO public.wallet_transactions (
        wallet_id,
        amount_subunit,
        type,
        description,
        withdrawal_request_id
      ) VALUES (
        v_request.wallet_id,
        v_request.amount_subunit,
        'credit',
        'Withdrawal reversed — refunded to wallet',
        v_request.id
      );
    END IF;

    UPDATE public.withdrawal_requests
    SET
      status = p_status,
      paystack_transfer_code = COALESCE(p_paystack_transfer_code, paystack_transfer_code),
      error_message = p_error_msg,
      updated_at = NOW()
    WHERE id = v_request.id;
  END IF;
END;
$function$


CREATE OR REPLACE FUNCTION public.fn_log_status_change()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    -- Only insert if the status has actually changed
    IF (OLD.status IS DISTINCT FROM NEW.status) THEN
        INSERT INTO public.booking_timeline (booking_id, stage, notes)
        VALUES (
            NEW.id, 
            NEW.status, 
            'Status transitioned from ' || OLD.status::text || ' to ' || NEW.status::text
        );
    END IF;
    RETURN NEW;
END;
$function$


CREATE OR REPLACE FUNCTION public.fn_sync_profile_fullname()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  NEW.fullname := NULLIF(
    trim(
      concat_ws(
        ' ',
        nullif(trim(coalesce(NEW.firstname, '')), ''),
        nullif(trim(coalesce(NEW.middlename, '')), ''),
        nullif(trim(coalesce(NEW.lastname, '')), '')
      )
    ),
    ''
  );

  RETURN NEW;
END;
$function$


CREATE OR REPLACE FUNCTION public.fn_update_deduction_rule(p_rule_name text, p_new_rate numeric, p_is_fixed boolean DEFAULT false)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN
    -- 1. Retire the currently active rule
    UPDATE public.deduction_rules 
    SET 
        end_date = NOW(), 
        is_active = false 
    WHERE 
        name = p_rule_name 
        AND is_active = true;

    -- 2. Insert the new version of the rule
    INSERT INTO public.deduction_rules (
        name, 
        rate_percentage, 
        is_fixed_amount, 
        start_date, 
        is_active
    )
    VALUES (
        p_rule_name, 
        CASE WHEN p_is_fixed THEN 0 ELSE p_new_rate END,
        p_is_fixed,
        NOW(),
        true
    );
END;
$function$


