CREATE OR REPLACE FUNCTION public.get_active_pricing_rule()
 RETURNS TABLE(pricing_version text, currency text, same_day_surcharge_bps integer, weekend_surcharge_bps integer, recurring_weekly_discount_bps integer, recurring_monthly_discount_bps integer)
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT
    pr.pricing_version,
    pr.currency,
    pr.same_day_surcharge_bps,
    pr.weekend_surcharge_bps,
    pr.recurring_weekly_discount_bps,
    pr.recurring_monthly_discount_bps
  FROM public.pricing_rules pr
  WHERE pr.is_active = true
    AND (pr.effective_from IS NULL OR pr.effective_from <= now())
    AND (pr.effective_to IS NULL OR pr.effective_to > now())
  ORDER BY pr.updated_at DESC
  LIMIT 1;
$function$


CREATE OR REPLACE FUNCTION public.get_ai_match_settings_admin()
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
BEGIN
  IF auth.uid() IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'Not authenticated');
  END IF;

  IF NOT public.has_role('admin') THEN
    RETURN jsonb_build_object('success', false, 'error', 'Admin role required');
  END IF;

  RETURN jsonb_build_object(
    'success', true,
    'settings', public.get_ai_match_settings(),
    'updated_at', (
      SELECT pc.updated_at
      FROM public.platform_config pc
      WHERE pc.key = 'ai_match_settings'
    )
  );
END;
$function$


CREATE OR REPLACE FUNCTION public.get_available_booking_days(p_timezone text DEFAULT 'UTC'::text, p_duration_hours numeric DEFAULT 3.0, p_days_ahead integer DEFAULT 14)
 RETURNS TABLE(booking_date date)
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_today date;
BEGIN
  v_today := (now() AT TIME ZONE p_timezone)::date;

  RETURN QUERY
  SELECT d::date
  FROM generate_series(
    v_today,
    v_today + (p_days_ahead - 1),
    interval '1 day'
  ) d
  WHERE EXISTS (
    SELECT 1
    FROM public.get_available_timeslots(
      d::date,
      p_timezone,
      p_duration_hours
    )
  );
END;
$function$


CREATE OR REPLACE FUNCTION public.get_available_timeslots(p_booking_date date, p_timezone text DEFAULT 'UTC'::text, p_duration_hours numeric DEFAULT NULL::numeric, p_exclude_booking_id uuid DEFAULT NULL::uuid)
 RETURNS TABLE(time_12h text, time_24h text, same_day_cutoff numeric, travel_buffer numeric, work_day_start numeric, work_day_end numeric, slot_interval_minutes integer, duration_hours numeric, disable_same_day_booking boolean, is_meta_row boolean)
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_same_day_cutoff numeric;
  v_travel_buffer numeric;
  v_work_day_start numeric;
  v_work_day_end numeric;

  v_slot_interval_minutes int := 30;

  v_duration numeric;
  v_now_local timestamp;

  v_start_minute int;
  v_latest_start_minute int;

  v_disable_same_day_booking boolean;
BEGIN
  -- p_exclude_booking_id: accepted for client RPC compatibility (slot list uses work-hour rules only).

  SELECT value_numeric INTO v_same_day_cutoff
  FROM booking_settings
  WHERE key = 'same_day_cutoff';

  SELECT value_numeric INTO v_travel_buffer
  FROM booking_settings
  WHERE key = 'travel_buffer';

  SELECT value_numeric INTO v_work_day_start
  FROM booking_settings
  WHERE key = 'work_day_start';

  SELECT value_numeric INTO v_work_day_end
  FROM booking_settings
  WHERE key = 'work_day_end';

  v_same_day_cutoff := COALESCE(v_same_day_cutoff, 24.0);
  v_travel_buffer   := COALESCE(v_travel_buffer, 1.0);
  v_work_day_start  := COALESCE(v_work_day_start, 5.0);
  v_work_day_end    := COALESCE(v_work_day_end, 17.0);

  v_duration := COALESCE(p_duration_hours, 3.0);

  IF v_duration <= 0 OR v_duration > 12 THEN
    RETURN QUERY
    SELECT
      NULL::text,
      NULL::text,
      v_same_day_cutoff,
      v_travel_buffer,
      v_work_day_start,
      v_work_day_end,
      v_slot_interval_minutes,
      v_duration,
      false,
      true;
    RETURN;
  END IF;

  v_now_local := now() AT TIME ZONE p_timezone;

  v_disable_same_day_booking :=
    p_booking_date = v_now_local::date
    AND (
      EXTRACT(HOUR FROM v_now_local)
      + EXTRACT(MINUTE FROM v_now_local) / 60.0
    ) >= v_same_day_cutoff;

  v_start_minute := floor(v_work_day_start * 60)::int;
  v_latest_start_minute :=
    floor((v_work_day_end - v_duration - v_travel_buffer) * 60)::int;

  RETURN QUERY
  WITH candidates AS (
    SELECT generate_series(
      v_start_minute,
      v_latest_start_minute,
      v_slot_interval_minutes
    ) AS minute_of_day
    WHERE v_latest_start_minute >= v_start_minute
  ),
  labeled AS (
    SELECT
      minute_of_day,
      (minute_of_day / 60)::int AS h24,
      (minute_of_day % 60)::int AS m
    FROM candidates
  ),
  stamped AS (
    SELECT
      (p_booking_date::timestamp
        + (h24 * interval '1 hour')
        + (m  * interval '1 minute')) AS ts,
      h24, m
    FROM labeled
  ),
  formatted AS (
    SELECT
      to_char(ts, 'FMHH12:MI AM') AS time_12h,
      to_char(ts, 'HH24:MI')      AS time_24h,
      h24, m
    FROM stamped
  ),
  slots AS (
    SELECT
      f.time_12h,
      f.time_24h,
      v_same_day_cutoff           AS same_day_cutoff,
      v_travel_buffer             AS travel_buffer,
      v_work_day_start            AS work_day_start,
      v_work_day_end              AS work_day_end,
      v_slot_interval_minutes     AS slot_interval_minutes,
      v_duration                  AS duration_hours,
      v_disable_same_day_booking  AS disable_same_day_booking,
      false                       AS is_meta_row,
      (f.h24 * 60 + f.m)          AS sort_key
    FROM formatted f
    WHERE
      NOT v_disable_same_day_booking
      AND public.validate_booking_timeslot_24h(
        f.time_24h,
        v_duration,
        p_booking_date,
        p_timezone
      ) = true
  ),
  unioned AS (
    SELECT
      s.time_12h,
      s.time_24h,
      s.same_day_cutoff,
      s.travel_buffer,
      s.work_day_start,
      s.work_day_end,
      s.slot_interval_minutes,
      s.duration_hours,
      s.disable_same_day_booking,
      s.is_meta_row,
      s.sort_key
    FROM slots s

    UNION ALL

    SELECT
      NULL::text AS time_12h,
      NULL::text AS time_24h,
      v_same_day_cutoff,
      v_travel_buffer,
      v_work_day_start,
      v_work_day_end,
      v_slot_interval_minutes,
      v_duration,
      v_disable_same_day_booking,
      true AS is_meta_row,
      NULL::int AS sort_key
    WHERE NOT EXISTS (SELECT 1 FROM slots)
  )
  SELECT
    u.time_12h,
    u.time_24h,
    u.same_day_cutoff,
    u.travel_buffer,
    u.work_day_start,
    u.work_day_end,
    u.slot_interval_minutes,
    u.duration_hours,
    u.disable_same_day_booking,
    u.is_meta_row
  FROM unioned u
  ORDER BY u.sort_key NULLS LAST;
END;
$function$


CREATE OR REPLACE FUNCTION public.get_available_timeslots_old(p_booking_date date, p_timezone text DEFAULT 'UTC'::text, p_duration_hours numeric DEFAULT NULL::numeric)
 RETURNS TABLE(time_12h text, time_24h text, same_day_cutoff numeric, travel_buffer numeric, work_day_start numeric, work_day_end numeric, slot_interval_minutes integer, duration_hours numeric, disable_same_day_booking boolean, is_meta_row boolean)
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_same_day_cutoff numeric;
  v_travel_buffer numeric;
  v_work_day_start numeric;
  v_work_day_end numeric;

  v_slot_interval_minutes int := 30;

  v_duration numeric;
  v_now_local timestamp;

  v_start_minute int;
  v_latest_start_minute int;

  v_disable_same_day_booking boolean;
BEGIN
  -- 1) Settings
  SELECT value_numeric INTO v_same_day_cutoff
  FROM booking_settings
  WHERE key = 'same_day_cutoff';

  SELECT value_numeric INTO v_travel_buffer
  FROM booking_settings
  WHERE key = 'travel_buffer';

  SELECT value_numeric INTO v_work_day_start
  FROM booking_settings
  WHERE key = 'work_day_start';

  SELECT value_numeric INTO v_work_day_end
  FROM booking_settings
  WHERE key = 'work_day_end';

  v_same_day_cutoff := COALESCE(v_same_day_cutoff, 24.0);
  v_travel_buffer   := COALESCE(v_travel_buffer, 1.0);
  v_work_day_start  := COALESCE(v_work_day_start, 5.0);
  v_work_day_end    := COALESCE(v_work_day_end, 17.0);

  -- 2) Duration
  v_duration := COALESCE(p_duration_hours, 3.0);

  IF v_duration <= 0 OR v_duration > 12 THEN
    RETURN QUERY
    SELECT
      NULL::text,
      NULL::text,
      v_same_day_cutoff,
      v_travel_buffer,
      v_work_day_start,
      v_work_day_end,
      v_slot_interval_minutes,
      v_duration,
      false,
      true;
    RETURN;
  END IF;

  -- 3) Local "now"
  v_now_local := now() AT TIME ZONE p_timezone;

  -- 4) Same-day cutoff (computed once)
  v_disable_same_day_booking :=
    p_booking_date = v_now_local::date
    AND (
      EXTRACT(HOUR FROM v_now_local)
      + EXTRACT(MINUTE FROM v_now_local) / 60.0
    ) >= v_same_day_cutoff;

  -- 5) Minute bounds
  v_start_minute := floor(v_work_day_start * 60)::int;

  -- Latest allowed start so (start + duration + buffer) <= work_day_end
  v_latest_start_minute :=
    floor((v_work_day_end - v_duration - v_travel_buffer) * 60)::int;

  -- 6) Return slots (or a meta-only row if none)
  RETURN QUERY
  WITH candidates AS (
    SELECT generate_series(
      v_start_minute,
      v_latest_start_minute,
      v_slot_interval_minutes
    ) AS minute_of_day
    WHERE v_latest_start_minute >= v_start_minute
  ),
  labeled AS (
    SELECT
      minute_of_day,
      (minute_of_day / 60)::int AS h24,
      (minute_of_day % 60)::int AS m
    FROM candidates
  ),
  stamped AS (
    SELECT
      (p_booking_date::timestamp
        + (h24 * interval '1 hour')
        + (m  * interval '1 minute')) AS ts,
      h24, m
    FROM labeled
  ),
  formatted AS (
    SELECT
      to_char(ts, 'FMHH12:MI AM') AS time_12h,
      to_char(ts, 'HH24:MI')      AS time_24h,
      h24, m
    FROM stamped
  ),
  slots AS (
    SELECT
      f.time_12h,
      f.time_24h,
      v_same_day_cutoff           AS same_day_cutoff,
      v_travel_buffer             AS travel_buffer,
      v_work_day_start            AS work_day_start,
      v_work_day_end              AS work_day_end,
      v_slot_interval_minutes     AS slot_interval_minutes,
      v_duration                  AS duration_hours,
      v_disable_same_day_booking  AS disable_same_day_booking,
      false                       AS is_meta_row,
      (f.h24 * 60 + f.m)          AS sort_key
    FROM formatted f
    WHERE
      NOT v_disable_same_day_booking
      AND public.validate_booking_timeslot_24h(
        f.time_24h,
        v_duration,
        p_booking_date,
        p_timezone
      ) = true
  ),
  unioned AS (
    SELECT
      s.time_12h,
      s.time_24h,
      s.same_day_cutoff,
      s.travel_buffer,
      s.work_day_start,
      s.work_day_end,
      s.slot_interval_minutes,
      s.duration_hours,
      s.disable_same_day_booking,
      s.is_meta_row,
      s.sort_key
    FROM slots s

    UNION ALL

    -- Meta-only row if no slots are returned (still provides settings + disable flag)
    SELECT
      NULL::text AS time_12h,
      NULL::text AS time_24h,
      v_same_day_cutoff,
      v_travel_buffer,
      v_work_day_start,
      v_work_day_end,
      v_slot_interval_minutes,
      v_duration,
      v_disable_same_day_booking,
      true AS is_meta_row,
      NULL::int AS sort_key
    WHERE NOT EXISTS (SELECT 1 FROM slots)
  )
  SELECT
    u.time_12h,
    u.time_24h,
    u.same_day_cutoff,
    u.travel_buffer,
    u.work_day_start,
    u.work_day_end,
    u.slot_interval_minutes,
    u.duration_hours,
    u.disable_same_day_booking,
    u.is_meta_row
  FROM unioned u
  ORDER BY u.sort_key NULLS LAST;

END;
$function$


CREATE OR REPLACE FUNCTION public.get_best_available_cleaners(p_date date, p_time time without time zone, p_duration numeric, p_lat double precision, p_lng double precision, p_max_distance_meters integer, p_requested_services text[], p_exclude_booking_id uuid DEFAULT NULL::uuid, p_requested_category service_category DEFAULT NULL::service_category)
 RETURNS TABLE(cleaner_id uuid, cleaner_name text, avatar_url text, bio text, hourly_rate numeric, rating double precision, distance_meters double precision, final_score double precision, company_name text, team_size integer, team_role text, specialties text[])
 LANGUAGE plpgsql
 STABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_cust_id uuid := auth.uid();
  v_booking_range tstzrange;
  v_cust_loc geography := ST_SetSRID(ST_MakePoint(p_lng, p_lat), 4326)::geography;
BEGIN
  IF v_cust_id IS NULL
     AND current_setting('app.system_cleaner_discovery', true) IS DISTINCT FROM '1'
  THEN
    RAISE EXCEPTION 'Not authorized';
  END IF;

  v_booking_range := tstzrange(
    (p_date + p_time)::timestamptz,
    (p_date + p_time + (p_duration || ' hours')::interval)::timestamptz,
    '[)'
  );

  RETURN QUERY
  WITH available_cleaners AS (
    SELECT
      cd.user_id AS cleaner_user_id,
      p.fullname AS cleaner_fullname,
      p.avatar_url AS profile_avatar_url,
      COALESCE(cd.bio, p.bio) AS profile_bio,
      cd.hourly_rate AS cleaner_hourly_rate,
      cd.rating AS cleaner_rating,
      cd.specialties AS cleaner_specialties,
      tb.company_name AS team_company_name,
      tb.team_role AS team_role,
      COALESCE(tb.team_size, 0) AS team_co_count,
      COALESCE(cd.base_location::geography, p.location_wkt) AS effective_location,
      ST_Distance(
        COALESCE(cd.base_location::geography, p.location_wkt),
        v_cust_loc
      )::float AS dist
    FROM public.cleaner_data cd
    JOIN public.profiles p ON p.user_id = cd.user_id
    LEFT JOIN LATERAL (
      SELECT b.company_name, b.team_role, b.team_size
      FROM public.cleaner_team_branding_for(cd.user_id) b
      LIMIT 1
    ) tb ON true
    WHERE cd.status = 'active'
      AND cd.verified = true
      AND COALESCE(cd.base_location::geography, p.location_wkt) IS NOT NULL
      AND public.is_profile_discoverable_by_others(p)
      AND cd.user_id IS DISTINCT FROM COALESCE(
        v_cust_id,
        (SELECT b.customer_id FROM public.bookings b WHERE b.id = p_exclude_booking_id LIMIT 1)
      )
      AND ST_DWithin(
        COALESCE(cd.base_location::geography, p.location_wkt),
        v_cust_loc,
        LEAST(
          COALESCE(cd.max_travel_distance_meters, p_max_distance_meters),
          p_max_distance_meters
        )
      )
      AND (
        p_requested_category IS NULL
        OR p_requested_category = ANY(cd.service_categories)
      )
      AND cardinality(COALESCE(cd.specialties, ARRAY[]::text[])) > 0
      AND (
        cardinality(COALESCE(p_requested_services, ARRAY[]::text[])) = 0
        OR EXISTS (
          SELECT 1
          FROM unnest(p_requested_services) s
          WHERE s = ANY(COALESCE(cd.specialties, ARRAY[]::text[]))
        )
      )
      AND NOT EXISTS (
        SELECT 1
        FROM public.bookings b
        WHERE b.cleaner_id = cd.user_id
          AND b.booking_period && v_booking_range
          AND b.status != 'cancelled'
          AND (
            p_exclude_booking_id IS NULL
            OR b.id <> p_exclude_booking_id
          )
      )
      AND NOT EXISTS (
        SELECT 1
        FROM public.cleaner_availability_exceptions cae
        WHERE cae.cleaner_id = cd.user_id
          AND cae.exception_date = p_date
      )
  ),
  scored_cleaners AS (
    SELECT
      ac.*,
      CASE
        WHEN cardinality(COALESCE(p_requested_services, ARRAY[]::text[])) > 0
        THEN (
          SELECT count(*)::float / cardinality(p_requested_services)
          FROM unnest(p_requested_services) s
          WHERE s = ANY(COALESCE(ac.cleaner_specialties, ARRAY[]::text[]))
        ) * 40
        ELSE 20
      END AS s_score
    FROM available_cleaners ac
  )
  SELECT
    sc.cleaner_user_id AS cleaner_id,
    sc.cleaner_fullname AS cleaner_name,
    sc.profile_avatar_url AS avatar_url,
    sc.profile_bio AS bio,
    sc.cleaner_hourly_rate AS hourly_rate,
    sc.cleaner_rating::float AS rating,
    sc.dist::float AS distance_meters,
    (
      (GREATEST(0, (1.0 - (sc.dist / p_max_distance_meters))) * 30)
      + (COALESCE(sc.cleaner_rating, 0) / 5.0 * 30)
      + sc.s_score
    )::float AS final_score,
    sc.team_company_name AS company_name,
    sc.team_co_count AS team_size,
    sc.team_role AS team_role,
    COALESCE(sc.cleaner_specialties, ARRAY[]::text[]) AS specialties
  FROM scored_cleaners sc
  ORDER BY final_score DESC, sc.dist ASC;
END;
$function$


CREATE OR REPLACE FUNCTION public.get_best_available_cleaners_old(p_date date, p_time time without time zone, p_duration numeric, p_lat double precision, p_lng double precision, p_max_distance_meters integer, p_requested_services text[])
 RETURNS TABLE(cleaner_id uuid, cleaner_name text, avatar_url text, bio text, hourly_rate numeric, rating double precision, distance_meters double precision, final_score double precision)
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_cust_id uuid := auth.uid();
  v_booking_range tstzrange;
  v_cust_loc geography := ST_SetSRID(ST_MakePoint(p_lng, p_lat), 4326)::geography;
BEGIN
  IF v_cust_id IS NULL THEN
    RAISE EXCEPTION 'Not authorized';
  END IF;

  v_booking_range := tstzrange(
    (p_date + p_time)::timestamptz,
    (p_date + p_time + (p_duration || ' hours')::interval)::timestamptz,
    '[)'
  );

  RETURN QUERY
  WITH available_cleaners AS (
    SELECT
      cd.user_id AS cleaner_user_id,
      p.fullname AS cleaner_fullname,
      p.avatar_url AS profile_avatar_url,
      COALESCE(cd.bio, p.bio) AS profile_bio,
      cd.hourly_rate AS cleaner_hourly_rate,
      cd.rating AS cleaner_rating,
      cd.skills AS cleaner_skills,
      cd.specialties AS cleaner_specialties,
      COALESCE(cd.base_location::geography, p.location_wkt) AS effective_location,
      ST_Distance(
        COALESCE(cd.base_location::geography, p.location_wkt),
        v_cust_loc
      )::float AS dist
    FROM public.cleaner_data cd
    JOIN public.profiles p ON p.user_id = cd.user_id
    WHERE cd.status = 'active'
      AND cd.verified = true
      AND COALESCE(cd.base_location::geography, p.location_wkt) IS NOT NULL
      AND (
        auth.uid() = cd.user_id
        OR public.is_profile_discoverable_by_others(p)
      )
      AND ST_DWithin(
        COALESCE(cd.base_location::geography, p.location_wkt),
        v_cust_loc,
        LEAST(
          COALESCE(cd.max_travel_distance_meters, p_max_distance_meters),
          p_max_distance_meters
        )
      )
      AND NOT EXISTS (
        SELECT 1
        FROM public.bookings b
        WHERE b.cleaner_id = cd.user_id
          AND b.booking_period && v_booking_range
          AND b.status != 'cancelled'
      )
      AND NOT EXISTS (
        SELECT 1
        FROM public.cleaner_availability_exceptions cae
        WHERE cae.cleaner_id = cd.user_id
          AND cae.exception_date = p_date
      )
  ),
  scored_cleaners AS (
    SELECT
      ac.cleaner_user_id,
      ac.cleaner_fullname,
      ac.profile_avatar_url,
      ac.profile_bio,
      ac.cleaner_hourly_rate,
      ac.cleaner_rating,
      ac.cleaner_skills,
      ac.cleaner_specialties,
      ac.dist,
      CASE
        WHEN cardinality(COALESCE(p_requested_services, ARRAY[]::text[])) > 0
        THEN (
          SELECT count(*)::float / cardinality(p_requested_services)
          FROM unnest(p_requested_services) s
          WHERE s = ANY(COALESCE(ac.cleaner_skills, ARRAY[]::text[]))
             OR s = ANY(COALESCE(ac.cleaner_specialties, ARRAY[]::text[]))
        ) * 40
        ELSE 20
      END AS s_score
    FROM available_cleaners ac
  )
  SELECT
    sc.cleaner_user_id AS cleaner_id,
    sc.cleaner_fullname AS cleaner_name,
    sc.profile_avatar_url AS avatar_url,
    sc.profile_bio AS bio,
    sc.cleaner_hourly_rate AS hourly_rate,
    sc.cleaner_rating::float AS rating,
    sc.dist::float AS distance_meters,
    (
      (GREATEST(0, (1.0 - (sc.dist / p_max_distance_meters))) * 30)
      + (COALESCE(sc.cleaner_rating, 0) / 5.0 * 30)
      + sc.s_score
    )::float AS final_score
  FROM scored_cleaners sc
  ORDER BY final_score DESC, sc.dist ASC;
END;
$function$


CREATE OR REPLACE FUNCTION public.get_booking_contact_phone(p_booking_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_uid uuid := auth.uid();
  v_row public.bookings%ROWTYPE;
  v_contact_user_id uuid;
  v_phone text;
BEGIN
  IF v_uid IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'not_authenticated');
  END IF;

  IF p_booking_id IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'missing_booking_id');
  END IF;

  SELECT * INTO v_row
  FROM public.bookings
  WHERE id = p_booking_id;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'not_found');
  END IF;

  IF v_row.status NOT IN ('confirmed', 'scheduled', 'en_route', 'arrived', 'in_progress') THEN
    RETURN jsonb_build_object('success', false, 'error', 'booking_not_active');
  END IF;

  IF v_row.status IN ('confirmed', 'scheduled')
    AND v_row.scheduled_at_utc IS NOT NULL
    AND v_row.scheduled_at_utc <= now() THEN
    RETURN jsonb_build_object('success', false, 'error', 'booking_not_active');
  END IF;

  -- Mid-visit statuses stay contactable past the scheduled slot, but only on
  -- the appointment day (service TZ). Mirrors bookingAllowsBookingContact in
  -- the app: a booking never marked complete must not expose phone numbers
  -- indefinitely.
  IF v_row.status IN ('en_route', 'arrived', 'in_progress')
    AND v_row.scheduled_date IS NOT NULL
    AND v_row.scheduled_date <>
      (now() AT TIME ZONE COALESCE(NULLIF(trim(v_row.timezone_name), ''), 'Africa/Accra'))::date THEN
    RETURN jsonb_build_object('success', false, 'error', 'booking_not_active');
  END IF;

  IF v_uid = v_row.customer_id AND v_row.cleaner_id IS NOT NULL THEN
    v_contact_user_id := v_row.cleaner_id;
  ELSIF v_uid = v_row.cleaner_id AND v_row.customer_id IS NOT NULL THEN
    v_contact_user_id := v_row.customer_id;
  ELSE
    RETURN jsonb_build_object('success', false, 'error', 'not_authorized');
  END IF;

  SELECT phone INTO v_phone
  FROM public.users
  WHERE id = v_contact_user_id;

  IF v_phone IS NULL OR trim(v_phone) = '' THEN
    RETURN jsonb_build_object('success', false, 'error', 'phone_unavailable');
  END IF;

  RETURN jsonb_build_object(
    'success', true,
    'phone', trim(v_phone),
    'contact_user_id', v_contact_user_id
  );
END;
$function$


CREATE OR REPLACE FUNCTION public.get_cleaner_availability_by_id(p_cleaner_id uuid, p_date date, p_time time without time zone, p_duration numeric, p_timezone text DEFAULT 'UTC'::text, p_exclude_booking_id uuid DEFAULT NULL::uuid)
 RETURNS TABLE(id uuid, fullname text, avatar_url text, hourly_rate numeric, is_available boolean)
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_start_local timestamp;
  v_end_local timestamp;
  v_requested_range tstzrange;
BEGIN
  v_start_local := (p_date + p_time)::timestamp;
  v_end_local := v_start_local + (p_duration * interval '1 hour') + interval '1 hour';

  v_requested_range := tstzrange(
    (v_start_local AT TIME ZONE p_timezone),
    (v_end_local AT TIME ZONE p_timezone),
    '[)'
  );

  RETURN QUERY
  SELECT
    cd.user_id,
    p.fullname,
    p.avatar_url,
    cd.hourly_rate,
    NOT EXISTS (
      SELECT 1
      FROM public.bookings b
      WHERE b.cleaner_id = p_cleaner_id
        AND b.booking_period && v_requested_range
        AND b.status IS DISTINCT FROM 'cancelled'
        AND (
          p_exclude_booking_id IS NULL
          OR b.id <> p_exclude_booking_id
        )
    ) AS is_available
  FROM public.cleaner_data cd
  JOIN public.profiles p ON p.id = cd.user_id
  WHERE cd.user_id = p_cleaner_id
    AND cd.status = 'active';
END;
$function$


CREATE OR REPLACE FUNCTION public.get_cleaner_availability_by_id_old(p_cleaner_id uuid, p_date date, p_time time without time zone, p_duration numeric, p_timezone text DEFAULT 'UTC'::text)
 RETURNS TABLE(id uuid, fullname text, avatar_url text, hourly_rate numeric, is_available boolean)
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
    v_start_local timestamp;
    v_end_local   timestamp;
    v_requested_range tstzrange;
BEGIN
    -- Interpret p_date + p_time in the given timezone, then convert
    v_start_local := (p_date + p_time)::timestamp;
    v_end_local   := v_start_local + (p_duration * interval '1 hour') + interval '1 hour';

    v_requested_range := tstzrange(
        (v_start_local AT TIME ZONE p_timezone),
        (v_end_local   AT TIME ZONE p_timezone),
        '[)'
    );

    RETURN QUERY
    SELECT
        cd.user_id,
        p.fullname,
        p.avatar_url,
        cd.hourly_rate,
        NOT EXISTS (
            SELECT 1
            FROM public.bookings b
            WHERE b.cleaner_id = p_cleaner_id
              AND b.booking_period && v_requested_range
              AND b.status IS DISTINCT FROM 'cancelled'
        ) AS is_available
    FROM public.cleaner_data cd
    JOIN public.profiles p ON p.id = cd.user_id
    WHERE cd.user_id = p_cleaner_id
      AND cd.status = 'active';
END;
$function$


CREATE OR REPLACE FUNCTION public.get_cleaner_by_booking_slug(p_slug text)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_slug text := lower(trim(coalesce(p_slug, '')));
  v_row record;
BEGIN
  IF v_slug = '' OR v_slug !~ '^[23456789abcdefghjkmnpqrstuvwxyz]{8}$' THEN
    RETURN jsonb_build_object('success', false, 'error', 'invalid_slug');
  END IF;

  SELECT
    cd.user_id,
    coalesce(nullif(trim(p.fullname), ''), nullif(trim(p.firstname), ''), 'Cleaner') as cleaner_name,
    p.avatar_url,
    cd.rating,
    cd.hourly_rate,
    coalesce(cd.bio, p.bio) as bio,
    cd.service_categories,
    cd.status,
    cd.verified,
    tb.company_name,
    tb.team_role
  INTO v_row
  FROM public.cleaner_data cd
  JOIN LATERAL (
    SELECT p.*
    FROM public.profiles p
    WHERE p.user_id = cd.user_id
       OR p.id = cd.user_id
    LIMIT 1
  ) p ON true
  LEFT JOIN LATERAL (
    SELECT b.company_name, b.team_role
    FROM public.cleaner_team_branding_for(cd.user_id) b
    LIMIT 1
  ) tb ON true
  WHERE cd.booking_slug = v_slug
    AND cd.status = 'active'
    AND cd.verified = true
    AND public.is_profile_discoverable_by_others(p)
  LIMIT 1;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'not_found');
  END IF;

  RETURN jsonb_build_object(
    'success', true,
    'cleaner', jsonb_build_object(
      'id', v_row.user_id,
      'name', v_row.cleaner_name,
      'avatar_url', v_row.avatar_url,
      'rating', coalesce(v_row.rating, 0),
      'hourly_rate', coalesce(v_row.hourly_rate, 0),
      'bio', v_row.bio,
      'service_categories', coalesce(to_jsonb(v_row.service_categories), '[]'::jsonb),
      'company_name', v_row.company_name,
      'team_role', v_row.team_role
    )
  );
END;
$function$


CREATE OR REPLACE FUNCTION public.get_cleaner_hourly_rate_limits()
 RETURNS jsonb
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT COALESCE(
    (
      SELECT value
      FROM public.platform_config
      WHERE key = 'cleaner_hourly_rate_limits'
    ),
    jsonb_build_object('min', 10, 'max', 100, 'default', 50)
  );
$function$


CREATE OR REPLACE FUNCTION public.get_cleaner_profile_v1(target_user_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_profile public.profiles%ROWTYPE;
  v_user_id uuid;
  v_team jsonb;
  result jsonb;
BEGIN
  SELECT *
  INTO v_profile
  FROM public.profiles p
  WHERE p.id = target_user_id
     OR p.user_id = target_user_id
  LIMIT 1;

  IF NOT FOUND THEN
    RETURN jsonb_build_object(
      'profile', NULL,
      'cleaner_data', NULL,
      'verification', NULL,
      'team', NULL
    );
  END IF;

  IF auth.uid() IS DISTINCT FROM v_profile.id
     AND auth.uid() IS DISTINCT FROM v_profile.user_id
     AND NOT public.is_profile_discoverable_by_others(v_profile) THEN
    RETURN jsonb_build_object(
      'profile', NULL,
      'cleaner_data', NULL,
      'verification', NULL,
      'team', NULL
    );
  END IF;

  v_user_id := COALESCE(v_profile.user_id, v_profile.id);

  SELECT jsonb_build_object(
    'company_name', b.company_name,
    'team_role', b.team_role,
    'team_size', b.team_size
  )
  INTO v_team
  FROM public.cleaner_team_branding_for(v_user_id) b
  LIMIT 1;

  SELECT jsonb_build_object(
    'profile', to_jsonb(v_profile),
    'cleaner_data', (SELECT to_jsonb(cd) FROM cleaner_data cd WHERE cd.user_id = v_user_id),
    'verification', jsonb_build_object(
      'checks', jsonb_build_object(
        'identity', (
          EXISTS (
            SELECT 1 FROM cleaner_applications ca
            WHERE ca.user_id = v_user_id
              AND (ca.kyc_status = 'verified' OR ca.kyc_review_answer = 'GREEN')
          )
          OR (
            EXISTS (
              SELECT 1 FROM cleaner_verifications cv
              WHERE cv.id = v_user_id
                AND cv.id_front_url IS NOT NULL
                AND cv.id_back_url IS NOT NULL
            )
            AND EXISTS (
              SELECT 1 FROM cleaner_applications ca
              WHERE ca.user_id = v_user_id AND ca.status = 'approved'
            )
          )
        ),
        'reference', EXISTS (
          SELECT 1 FROM cleaner_applications ca
          WHERE ca.user_id = v_user_id
            AND ca.status = 'approved'
            AND NULLIF(BTRIM(ca.reference1_name), '') IS NOT NULL
            AND NULLIF(BTRIM(ca.reference1_phone), '') IS NOT NULL
        ),
        'police_report', EXISTS (
          SELECT 1 FROM cleaner_verifications cv
          WHERE cv.id = v_user_id AND cv.police_report_url IS NOT NULL
        )
      )
    ),
    'team', v_team
  )
  INTO result;

  RETURN result;
END;
$function$


CREATE OR REPLACE FUNCTION public.get_cleaner_profile_with_reviews_and_stats(p_user_id uuid)
 RETURNS TABLE(cleaner_data jsonb, reviews_data jsonb, jobs_completed bigint, repeat_customer_percent integer)
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_cleaner RECORD;
  v_review_count INT;
  v_jobs_completed BIGINT;
  v_repeat_pct INT;
  v_reviews_json JSONB;
BEGIN
  -- Get cleaner_data + user + profile (use user_profiles; if your schema uses "profiles", replace user_profiles with profiles)
  SELECT
    cd.user_id,
    cd.hourly_rate,
    cd.rating,
    cd.verified,
    cd.service_areas,
    cd.skills,
    cd.years_experience,
    cd.certifications,
    cd.languages,
    u.email,
    u.phone,
    u.created_at AS user_created_at,
    COALESCE(up.fullname, TRIM(CONCAT(COALESCE(up.firstname, ''), ' ', COALESCE(up.lastname, ''))), 'Unknown') AS fullname,
    up.avatar_url,
    up.bio
  INTO v_cleaner
  FROM cleaner_data cd
  JOIN users u ON u.id = cd.user_id
  LEFT JOIN profiles up ON up.id = cd.user_id
  WHERE cd.user_id = p_user_id
    AND cd.status = 'active';

  IF NOT FOUND THEN
    RETURN;  -- 0 rows
  END IF;

  -- Review count for total_reviews
  SELECT COUNT(*)::INT INTO v_review_count
  FROM reviews
  WHERE reviewee_id = p_user_id;

  -- Reviews array with reviewer name (from user_profiles)
  SELECT COALESCE(
    jsonb_agg(
      jsonb_build_object(
        'id', r.id,
        'customer_name', COALESCE(rev_fullname.fullname, TRIM(CONCAT(COALESCE(rev_fullname.firstname, ''), ' ', COALESCE(rev_fullname.lastname, ''))), 'Anonymous'),
        'rating', r.rating,
        'comment', r.comment,
        'created_at', r.created_at
      ) ORDER BY r.created_at DESC
    ),
    '[]'::jsonb
  ) INTO v_reviews_json
  FROM reviews r
  LEFT JOIN profiles rev_fullname ON rev_fullname.id = r.reviewer_id
  WHERE r.reviewee_id = p_user_id;

  -- Jobs completed and repeat customer % (one review per booking: % of unique customers who booked more than once)
  WITH completed AS (
    SELECT customer_id
    FROM bookings
    WHERE cleaner_id = p_user_id AND status = 'completed'
  ),
  by_cust AS (
    SELECT customer_id, COUNT(*) AS n
    FROM completed
    GROUP BY customer_id
  )
  SELECT
    (SELECT COUNT(*) FROM completed)::BIGINT,
    CASE
      WHEN (SELECT COUNT(*) FROM by_cust) = 0 THEN NULL
      ELSE ROUND(
        100.0 * (SELECT COUNT(*) FROM by_cust WHERE n > 1) / (SELECT COUNT(*) FROM by_cust)
      )::INT
    END
  INTO v_jobs_completed, v_repeat_pct;

  -- Build cleaner JSON (match CleanerProfile shape)
  cleaner_data := jsonb_build_object(
    'id', v_cleaner.user_id,
    'name', v_cleaner.fullname,
    'email', COALESCE(v_cleaner.email, ''),
    'phone', v_cleaner.phone,
    'profile_image', v_cleaner.avatar_url,
    'bio', v_cleaner.bio,
    'skills', COALESCE(v_cleaner.skills, '{}'),
    'service_areas', COALESCE(v_cleaner.service_areas, '{}'),
    'hourly_rate', COALESCE(v_cleaner.hourly_rate, 0),
    'rating', COALESCE(v_cleaner.rating, 0),
    'total_reviews', v_review_count,
    'years_experience', COALESCE(v_cleaner.years_experience, 0),
    'is_verified', COALESCE(v_cleaner.verified, false),
    'certifications', COALESCE(v_cleaner.certifications, '{}'),
    'languages', COALESCE(v_cleaner.languages, '{}'),
    'created_at', v_cleaner.user_created_at
  );

  reviews_data := v_reviews_json;
  jobs_completed := v_jobs_completed;
  repeat_customer_percent := v_repeat_pct;

  RETURN NEXT;
END;
$function$


CREATE OR REPLACE FUNCTION public.get_cleaner_transaction_history(p_start_date timestamp with time zone, p_end_date timestamp with time zone)
 RETURNS TABLE(id uuid, created_at timestamp with time zone, amount_subunit integer, type text, description text, status text)
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
    RETURN QUERY
    SELECT 
        wt.id, 
        wt.created_at, 
        wt.amount_subunit, 
        wt.type, 
        wt.description,
        'completed'::TEXT -- Wallet transactions are usually already completed
    FROM public.wallet_transactions wt
    JOIN public.wallets w ON wt.wallet_id = w.id
    WHERE w.user_id = auth.uid()
    AND wt.created_at BETWEEN p_start_date AND p_end_date -- FILTERING LOGIC
    ORDER BY wt.created_at DESC;
END;
$function$


CREATE OR REPLACE FUNCTION public.get_cleaner_wallet(p_user_id uuid)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_in_transit numeric;
    v_estimated numeric;
    v_total numeric;
BEGIN
    -- 1. Pending transfers or deposits
    SELECT COALESCE(SUM(amount), 0) INTO v_in_transit 
    FROM transactions WHERE user_id = p_user_id AND status = 'pending';

    -- 2. Available balance ready for payout
    SELECT COALESCE(SUM(amount), 0) INTO v_estimated 
    FROM transactions WHERE user_id = p_user_id AND status = 'available';

    -- 3. Historical total earned
    SELECT COALESCE(SUM(amount), 0) INTO v_total 
    FROM transactions WHERE user_id = p_user_id AND type = 'job_payment' AND status = 'success';

    RETURN json_build_object(
        'inTransit', v_in_transit,
        'estimatedPayout', v_estimated,
        'total', v_total
    );
END;
$function$


CREATE OR REPLACE FUNCTION public.get_cleaners_with_score(customer_id uuid, requested_services text[] DEFAULT '{}'::text[])
 RETURNS TABLE(cleaner_id uuid, cleaner_name text, avatar_url text, bio text, hourly_rate numeric, rating numeric, years_experience numeric, distance_km double precision, match_score double precision, skills text[], specialties text[], metric_distance_score double precision, metric_skill_score double precision)
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE 
    customer_loc geography;
BEGIN 
    -- Get customer location from profiles
    SELECT location_wkt INTO customer_loc FROM public.profiles WHERE id = customer_id;

    RETURN QUERY
    WITH cleaner_base AS (
        SELECT 
            p.id as cid,
            p.fullname,
            p.avatar_url as a_url, -- From profiles
            p.bio as c_bio,
            cd.hourly_rate as hr,
            cd.rating as rt,
            cd.years_experience as yexp,
            cd.skills as sk,
            cd.specialties as sp,
            ST_Distance(p.location_wkt, customer_loc) / 1000.0 as dist
        FROM public.cleaner_data cd
        JOIN public.profiles p ON p.id = cd.user_id
        WHERE cd.status = 'active'
    ),
    scored_cleaners AS (
        SELECT 
            *,
            GREATEST(0, (1.0 - (dist / 30.0))) * 30 as d_score,
            (rt / 5.0) * 30 as r_score,
            CASE 
                WHEN array_length(requested_services, 1) > 0 
                THEN (
                    SELECT count(*)::float / array_length(requested_services, 1) 
                    FROM unnest(requested_services) s 
                    WHERE s = ANY(sk) OR s = ANY(sp)
                ) * 40
                ELSE 20 
            END as s_score
        FROM cleaner_base
    )
    SELECT 
        cid,
        fullname,
        a_url,
        c_bio,
        hr,
        rt,
        yexp,
        dist,
        (d_score + r_score + s_score) as final_score,
        sk,
        sp,
        d_score,
        s_score
    FROM scored_cleaners
    ORDER BY final_score DESC;
END;$function$


CREATE OR REPLACE FUNCTION public.get_location_current_time(p_timezone text, p_duration_hours numeric)
 RETURNS TABLE(current_timestamp_tz timestamp with time zone, local_date date, local_time time without time zone, is_past_day_cutoff boolean, is_today_impossible boolean, latest_start_time time without time zone, same_day_cutoff_at timestamp with time zone)
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_now_at_location timestamp;
  v_work_day_end numeric;
  v_travel_buffer numeric;
  v_latest_start_decimal numeric;
  v_current_time_decimal numeric;
  v_cutoff_time time;
  v_same_day_cutoff_at_local timestamp;
BEGIN
  -- Fetch settings
  SELECT value_numeric
  INTO v_work_day_end
  FROM booking_settings
  WHERE key = 'work_day_end';

  SELECT value_numeric
  INTO v_travel_buffer
  FROM booking_settings
  WHERE key = 'travel_buffer';

  -- Fallbacks
  v_work_day_end := COALESCE(v_work_day_end, 17.0);   -- 5 PM
  v_travel_buffer := COALESCE(v_travel_buffer, 1.0);  -- 1 hour

  -- Local wall clock time at the service location
  v_now_at_location := now() AT TIME ZONE p_timezone;

  -- Latest allowed start time today:
  -- work day end - service duration - travel buffer
  v_latest_start_decimal := v_work_day_end - p_duration_hours - v_travel_buffer;

  -- Clamp to valid day range
  v_latest_start_decimal := GREATEST(0, LEAST(23.999722, v_latest_start_decimal));

  -- Current local time as decimal hours
  v_current_time_decimal :=
    EXTRACT(HOUR FROM v_now_at_location)
    + (EXTRACT(MINUTE FROM v_now_at_location) / 60.0)
    + (EXTRACT(SECOND FROM v_now_at_location) / 3600.0);

  -- Convert latest start decimal to time
  v_cutoff_time := make_time(
    floor(v_latest_start_decimal)::int,
    floor((v_latest_start_decimal - floor(v_latest_start_decimal)) * 60)::int,
    0
  );

  -- Local timestamp for today's cutoff
  v_same_day_cutoff_at_local := date_trunc('day', v_now_at_location) + v_cutoff_time;

  RETURN QUERY
  SELECT
    now() AS current_timestamp_tz,
    v_now_at_location::date AS local_date,
    v_now_at_location::time AS local_time,
    (v_now_at_location >= v_same_day_cutoff_at_local) AS is_past_day_cutoff,
    (v_current_time_decimal > v_latest_start_decimal) AS is_today_impossible,
    v_cutoff_time AS latest_start_time,
    (v_same_day_cutoff_at_local AT TIME ZONE p_timezone) AS same_day_cutoff_at;
END;
$function$


CREATE OR REPLACE FUNCTION public.get_my_cleaner_booking_link()
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_user uuid := auth.uid();
  v_slug text;
  v_candidate text;
begin
  if v_user is null then
    return jsonb_build_object('success', false, 'error', 'not_authenticated');
  end if;

  select booking_slug into v_slug
  from public.cleaner_data
  where user_id = v_user;

  if not found then
    return jsonb_build_object('success', false, 'error', 'cleaner_not_found');
  end if;

  while v_slug is null loop
    v_candidate := public.generate_cleaner_booking_slug();

    begin
      update public.cleaner_data
        set booking_slug = v_candidate
      where user_id = v_user
        and booking_slug is null
      returning booking_slug into v_slug;

      if v_slug is null then
        select booking_slug into v_slug from public.cleaner_data where user_id = v_user;
      end if;
    exception when unique_violation then
      v_slug := null;
    end;
  end loop;

  return jsonb_build_object(
    'success', true,
    'slug', v_slug,
    -- Server-side URL from platform_config.app_url (per Supabase project).
    -- Mobile app overrides with EXPO_PUBLIC_DOMAIN_URL when sharing.
    'url', public.resolve_app_base_url() || '/book/cleaner/' || v_slug
  );
end;
$function$


CREATE OR REPLACE FUNCTION public.get_my_cleaner_team()
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_uid uuid := auth.uid();
  v_company_name text;
  v_team_size int;
BEGIN
  IF v_uid IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'not_authenticated');
  END IF;

  SELECT ct.company_name
  INTO v_company_name
  FROM public.cleaner_teams ct
  WHERE ct.lead_cleaner_id = v_uid;

  v_team_size := public.cleaner_team_co_count(v_uid);

  RETURN jsonb_build_object(
    'success', true,
    'company_name', v_company_name,
    'team_size', v_team_size
  );
END;
$function$


CREATE OR REPLACE FUNCTION public.get_my_referral_info()
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_user uuid := auth.uid();
  v_code text;
  v_candidate_code text;
  v_referred_by uuid;
  v_referred_count bigint;
begin
  if v_user is null then
    return jsonb_build_object('success', false, 'error', 'not_authenticated');
  end if;

  select referral_code, referred_by
    into v_code, v_referred_by
  from users
  where id = v_user;

  if not found then
    return jsonb_build_object('success', false, 'error', 'user_not_found');
  end if;

  while v_code is null loop
    v_candidate_code := public.generate_referral_code();

    begin
      update users
        set referral_code = v_candidate_code
      where id = v_user
        and referral_code is null
      returning referral_code into v_code;

      if v_code is null then
        -- A concurrent first call won the race and set the code: the UPDATE
        -- matched zero rows. Re-read instead of looping forever.
        select referral_code into v_code from users where id = v_user;
      end if;
    exception when unique_violation then
      -- Extremely unlikely collision with another user's code: retry.
      v_code := null;
    end;
  end loop;

  select count(*) into v_referred_count from users where referred_by = v_user;

  return jsonb_build_object(
    'success', true,
    'referral_code', v_code,
    'referred_count', v_referred_count,
    'already_redeemed', v_referred_by is not null
  );
end;
$function$


CREATE OR REPLACE FUNCTION public.get_my_wallet_balance()
 RETURNS TABLE(balance integer, currency character varying)
