END;
$function$


CREATE OR REPLACE FUNCTION public.get_nearby_available_cleaners(p_latitude double precision, p_longitude double precision, p_radius_meters integer, p_scheduled_date date, p_start_time time without time zone, p_duration_hours integer)
 RETURNS TABLE(id uuid, fullname text, avatar_url text, distance_meters double precision, rating double precision)
 LANGUAGE sql
 STABLE
AS $function$WITH
origin AS (
  SELECT ST_SetSRID(ST_MakePoint(p_longitude, p_latitude), 4326)::geography AS g
),
booking AS (
  SELECT tstzrange(
    (p_scheduled_date + p_start_time)::timestamptz,
    (p_scheduled_date + p_start_time + (p_duration_hours || ' hours')::interval)::timestamptz,
    '[)'
  ) AS r
),
cleaners AS (
  SELECT
    p.id,
    p.fullname,
    p.avatar_url,
    cd.rating,
    cd.max_travel_distance_meters,
    COALESCE(cd.base_location::geography, p.location_wkt) AS effective_location
  FROM public.profiles p
  JOIN public.cleaner_data cd
    ON cd.user_id = p.id
  WHERE COALESCE(cd.base_location::geography, p.location_wkt) IS NOT NULL
    AND cd.status = 'active'::public.cleaner_status
    AND cd.verified = true
    AND COALESCE(cd.is_online, false) = true
    AND EXISTS (
      SELECT 1
      FROM public.user_roles ur
      WHERE ur.user_id = p.id
        AND ur.role_id = 'cleaner'
    )
)
SELECT
  c.id,
  c.fullname,
  c.avatar_url,
  d.distance_meters,
  c.rating::double precision AS rating
FROM cleaners c
CROSS JOIN origin o
CROSS JOIN booking bk
CROSS JOIN LATERAL (
  SELECT ST_Distance(c.effective_location, o.g) AS distance_meters
) d
WHERE ST_DWithin(c.effective_location, o.g, p_radius_meters)
  AND d.distance_meters <= COALESCE(c.max_travel_distance_meters, 30000)
  AND NOT EXISTS (
    SELECT 1
    FROM public.bookings b
    WHERE b.cleaner_id = c.id
      AND b.status <> 'cancelled'::public.booking_status
      AND b.booking_period && bk.r
  )
ORDER BY d.distance_meters ASC
LIMIT 200;$function$


CREATE OR REPLACE FUNCTION public.get_own_cleaner_location()
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_user_id uuid := auth.uid();
  v_lat     double precision;
  v_lng     double precision;
  v_max     integer;
  v_geom    geometry;
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'Not authorized';
  END IF;

  SELECT cd.base_location, cd.max_travel_distance_meters
    INTO v_geom, v_max
  FROM public.cleaner_data cd
  WHERE cd.user_id = v_user_id;

  IF v_geom IS NOT NULL THEN
    v_lat := ST_Y(v_geom);
    v_lng := ST_X(v_geom);
  END IF;

  RETURN jsonb_build_object(
    'has_location',                v_geom IS NOT NULL,
    'latitude',                    v_lat,
    'longitude',                   v_lng,
    'max_travel_distance_meters',  COALESCE(v_max, 30000)
  );
END;
$function$


CREATE OR REPLACE FUNCTION public.get_payment_split_config()
 RETURNS jsonb
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT jsonb_object_agg(key, value)
  FROM payment_split_config
  WHERE key IN ('tax_percentage', 'vendor_percentage');
$function$


CREATE OR REPLACE FUNCTION public.get_payout_system_logs()
 RETURNS TABLE(id bigint, status_code integer, content text, url text, created_at timestamp with time zone, delivery_status text)
 LANGUAGE sql
 SECURITY DEFINER
 SET search_path TO 'public', 'net'
AS $function$
  SELECT
    q.id,
    q.status_code,
    q.content,
    NULL::text AS url,
    NULL::timestamptz AS created_at,
    CASE
      WHEN q.timed_out THEN 'timeout'
      WHEN q.status_code >= 200 AND q.status_code < 300 THEN 'success'
      WHEN q.status_code >= 400 THEN 'failed'
      ELSE 'pending'
    END AS delivery_status
  FROM net._http_response q
  ORDER BY q.id DESC
  LIMIT 500;
$function$


CREATE OR REPLACE FUNCTION public.get_pending_booking_for_edit(p_customer_id uuid, p_booking_id uuid)
 RETURNS TABLE(id uuid, customer_id uuid, cleaner_id uuid, service_id integer, title text, scheduled_date date, scheduled_time time without time zone, duration_hours numeric, address text, special_instructions text, status booking_status, payment_status text, subscription_id uuid, home_size text, extra_task_ids text[], duration_adjustment numeric, duration_computed numeric, duration_final numeric, timezone_name text, cleaner_assigned_at timestamp with time zone, service_duration_option_id uuid, location_latitude double precision, location_longitude double precision, service jsonb)
 LANGUAGE sql
 STABLE
 SET search_path TO 'public'
AS $function$
  SELECT
    b.id,
    b.customer_id,
    b.cleaner_id,
    b.service_id,
    b.title,
    b.scheduled_date,
    b.scheduled_time,
    b.duration_hours,
    b.address,
    b.special_instructions,
    b.status,
    b.payment_status,
    b.subscription_id,
    b.home_size,
    b.extra_task_ids,
    b.duration_adjustment,
    b.duration_computed,
    b.duration_final,
    b.timezone_name,
    b.cleaner_assigned_at,
    b.service_duration_option_id,
    CASE
      WHEN b.location_coordinates IS NOT NULL
        THEN ST_Y(b.location_coordinates::geometry)
      ELSE NULL
    END AS location_latitude,
    CASE
      WHEN b.location_coordinates IS NOT NULL
        THEN ST_X(b.location_coordinates::geometry)
      ELSE NULL
    END AS location_longitude,
    to_jsonb(s.*) AS service
  FROM public.bookings b
  JOIN public.service_types s
    ON s.id = b.service_id
  WHERE b.id = p_booking_id
    AND b.customer_id = p_customer_id
    AND b.status IN ('pending', 'confirmed', 'scheduled')
    AND b.subscription_id IS NULL
  LIMIT 1;
$function$


CREATE OR REPLACE FUNCTION public.get_profile_location_coords(p_user_id uuid)
 RETURNS TABLE(location_wkt text, lat double precision, lng double precision)
 LANGUAGE sql
 STABLE
 SET search_path TO 'public', 'extensions'
AS $function$
  SELECT
    p.location_wkt::text,
    CASE
      WHEN p.location_wkt IS NOT NULL THEN ST_Y(p.location_wkt::geometry)
      ELSE NULL
    END AS lat,
    CASE
      WHEN p.location_wkt IS NOT NULL THEN ST_X(p.location_wkt::geometry)
      ELSE NULL
    END AS lng
  FROM public.profiles p
  WHERE p.id = p_user_id
    AND p.id = auth.uid();
$function$


