CREATE OR REPLACE FUNCTION public.inbox_notification_android_channel(p_type text)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT CASE p_type
    WHEN 'broadcast_assignment_offer' THEN 'job_offers'
    WHEN 'direct_assignment_offer' THEN 'job_offers'
    WHEN 'direct_assignment_reminder' THEN 'job_offers'
    WHEN 'job_offer' THEN 'job_offers'
    WHEN 'payment_received' THEN 'new_booking'
    WHEN 'booking_confirmed' THEN 'new_booking'
    WHEN 'booking_cancelled' THEN 'booking_cancellations'
    WHEN 'unassigned_booking_escalated' THEN 'booking_cancellations'
    WHEN 'new_message' THEN 'messages'
    WHEN 'cleaner_en_route' THEN 'cleaner_milestones'
    WHEN 'cleaner_arrived' THEN 'cleaner_milestones'
    ELSE 'booking_updates'
  END;
$function$


CREATE OR REPLACE FUNCTION public.inbox_notification_interruption_level(p_type text)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT CASE
    WHEN p_type IN (
      'cleaner_en_route',
      'cleaner_arrived',
      'booking_cancelled',
      'payment_required',
      'direct_assignment_offer',
      'direct_assignment_reminder'
    ) THEN 'time-sensitive'
    ELSE NULL
  END;
$function$


CREATE OR REPLACE FUNCTION public.increment_invite_code_usage(p_code text)
 RETURNS boolean
 LANGUAGE plpgsql
AS $function$
declare
  updated_rows int;
begin
  update invite_codes
  set uses = uses + 1,
      updated_at = now()
  where code = p_code
    and enabled = true
    and (expires_at is null or expires_at > now())
    and uses < max_uses;

  get diagnostics updated_rows = row_count;
  return updated_rows = 1;
end;
$function$


CREATE OR REPLACE FUNCTION public.insert_psk_transaction(p_booking_id uuid, p_user_id uuid, p_reference text, p_paystack_id bigint, p_amount numeric, p_fee_amount numeric, p_total_captured numeric, p_currency text, p_metadata jsonb)
 RETURNS psk_transaction
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_new_transaction public.psk_transaction;
BEGIN
    INSERT INTO public.psk_transaction (
        booking_id,
        user_id,
        reference,
        paystack_id,
        amount,
        fee_amount,
        total_captured,
        currency,
        metadata
    )
    VALUES (
        p_booking_id,
        p_user_id,
        p_reference,
        p_paystack_id,
        p_amount,
        p_fee_amount,
        p_total_captured,
        p_currency,
        p_metadata
    )
    RETURNING * INTO v_new_transaction;

    RETURN v_new_transaction;
END;
$function$


