CREATE OR REPLACE FUNCTION public.is_platform_fee_admin()
 RETURNS boolean
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  has_role_col boolean;
BEGIN
  -- Primary: user_roles
  IF EXISTS (
    SELECT 1 FROM public.user_roles
    WHERE user_id = auth.uid() AND role_id = 'admin'
  ) THEN
    RETURN true;
  END IF;
  -- Fallback: users.role if column exists
  SELECT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_schema = 'public' AND table_name = 'users' AND column_name = 'role'
  ) INTO has_role_col;
  IF has_role_col THEN
    RETURN (SELECT role FROM public.users WHERE id = auth.uid()) = 'admin';
  END IF;
  RETURN false;
END;
$function$


CREATE OR REPLACE FUNCTION public.is_profile_discoverable_by_others(p profiles)
