CREATE OR REPLACE FUNCTION public.sync_auth_user_to_public_user()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  meta_first text;
  meta_last text;
  meta_full text;
begin
  meta_first := nullif(trim(coalesce(new.raw_user_meta_data->>'first_name', '')), '');
  meta_last := nullif(trim(coalesce(new.raw_user_meta_data->>'last_name', '')), '');
  meta_full := nullif(
    trim(
      coalesce(
        new.raw_user_meta_data->>'full_name',
        new.raw_user_meta_data->>'name',
        concat_ws(' ', meta_first, meta_last)
      )
    ),
    ''
  );

  insert into public.users (id, email, phone, updated_at, last_updated)
  values (new.id, new.email, new.phone, now(), now())
  on conflict (id) do update
  set
    email = excluded.email,
    phone = coalesce(excluded.phone, public.users.phone),
    updated_at = now(),
    last_updated = now();

  insert into public.profiles (id, user_id, firstname, lastname, fullname, updated_at)
  values (new.id, new.id, meta_first, meta_last, meta_full, now())
  on conflict (id) do update
  set
    firstname = case
      when nullif(trim(coalesce(public.profiles.firstname, '')), '') is null
        then coalesce(excluded.firstname, public.profiles.firstname)
      else public.profiles.firstname
    end,
    lastname = case
      when nullif(trim(coalesce(public.profiles.lastname, '')), '') is null
        then coalesce(excluded.lastname, public.profiles.lastname)
      else public.profiles.lastname
    end,
    fullname = case
      when nullif(trim(coalesce(public.profiles.fullname, '')), '') is null
        then coalesce(excluded.fullname, public.profiles.fullname)
      else public.profiles.fullname
    end,
    updated_at = now();

  insert into public.user_roles (user_id, role_id)
  values (new.id, coalesce(new.raw_app_meta_data->>'role', 'customer'))
  on conflict (user_id, role_id) do nothing;

  return new;
end;
$function$


CREATE OR REPLACE FUNCTION public.sync_profile_name_from_payout(p_user_id uuid, p_payout_account_name text, p_previous_profile_name text DEFAULT NULL::text, p_payout_type text DEFAULT NULL::text, p_source text DEFAULT 'payout_name_mismatch'::text, p_apply boolean DEFAULT false)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_profile public.profiles%ROWTYPE;
  v_clean_name text;
  v_tokens text[];
  v_token_count integer;
  v_firstname text;
  v_middlename text;
  v_lastname text;
  v_existing_preferences jsonb;
  v_patch jsonb;
BEGIN
  IF p_user_id IS NULL THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', 'missing_user_id'
    );
  END IF;

  IF auth.uid() IS DISTINCT FROM p_user_id THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', 'not_allowed'
    );
  END IF;

  v_clean_name := nullif(trim(regexp_replace(coalesce(p_payout_account_name, ''), '\s+', ' ', 'g')), '');

  IF v_clean_name IS NULL THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', 'missing_payout_account_name'
    );
  END IF;

  SELECT *
  INTO v_profile
  FROM public.profiles
  WHERE id = p_user_id
  LIMIT 1;

  IF NOT FOUND THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', 'profile_not_found'
    );
  END IF;

  v_tokens := regexp_split_to_array(v_clean_name, '\s+');
  v_token_count := coalesce(array_length(v_tokens, 1), 0);

  IF v_token_count = 1 THEN
    v_firstname := v_tokens[1];
    v_middlename := NULL;
    v_lastname := NULL;
  ELSIF v_token_count = 2 THEN
    v_firstname := v_tokens[1];
    v_middlename := NULL;
    v_lastname := v_tokens[2];
  ELSE
    v_firstname := v_tokens[1];
    v_middlename := array_to_string(v_tokens[2:v_token_count - 1], ' ');
    v_lastname := v_tokens[v_token_count];
  END IF;

  v_existing_preferences := coalesce(v_profile.preferences, '{}'::jsonb);

  v_patch := jsonb_build_object(
    'payout_name_mismatch',
    jsonb_build_object(
      'flagged_at', coalesce(
        v_existing_preferences #>> '{payout_name_mismatch,flagged_at}',
        now()::text
      ),
      'profile_synced_at', CASE WHEN p_apply THEN now()::text ELSE NULL END,
      'profile_name', coalesce(p_previous_profile_name, v_profile.fullname),
      'payout_account_name', v_clean_name,
      'payout_type', p_payout_type,
      'source', p_source,
      'requires_review', true,
      'suggested_profile_name', jsonb_build_object(
        'firstname', v_firstname,
        'middlename', v_middlename,
        'lastname', v_lastname,
        'fullname', v_clean_name
      ),
      'previous_names', jsonb_build_object(
        'firstname', v_profile.firstname,
        'middlename', v_profile.middlename,
        'lastname', v_profile.lastname,
        'fullname', v_profile.fullname
      )
    )
  );

  IF p_apply THEN
    UPDATE public.profiles
    SET
      firstname = v_firstname,
      middlename = v_middlename,
      lastname = v_lastname,
      preferences = v_existing_preferences || v_patch,
      updated_at = now()
    WHERE id = p_user_id;
  ELSE
    UPDATE public.profiles
    SET
      preferences = v_existing_preferences || v_patch,
      updated_at = now()
    WHERE id = p_user_id;
  END IF;

  RETURN jsonb_build_object(
    'success', true,
    'applied', p_apply,
    'suggested', jsonb_build_object(
      'firstname', v_firstname,
      'middlename', v_middlename,
      'lastname', v_lastname,
      'fullname', v_clean_name
    )
  );
END;
$function$


