CREATE OR REPLACE FUNCTION public.update_my_hourly_rate(p_hourly_rate numeric)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_user uuid := auth.uid();
  v_limits jsonb;
  v_min numeric;
  v_max numeric;
BEGIN
  IF v_user IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'not_authenticated');
  END IF;

  SELECT value INTO v_limits
  FROM public.platform_config
  WHERE key = 'cleaner_hourly_rate_limits';

  v_min := COALESCE((v_limits->>'min')::numeric, 10);
  v_max := COALESCE((v_limits->>'max')::numeric, 100);

  IF p_hourly_rate IS NULL OR p_hourly_rate < v_min OR p_hourly_rate > v_max THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', 'invalid_rate',
      'min', v_min,
      'max', v_max
    );
  END IF;

  UPDATE public.cleaner_data
  SET hourly_rate = p_hourly_rate,
      rate_set_at = now(),
      updated_at = now()
  WHERE user_id = v_user;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'cleaner_not_found');
  END IF;

  RETURN jsonb_build_object(
    'success', true,
    'hourly_rate', p_hourly_rate,
    'rate_set_at', now()
  );
END;
$function$


CREATE OR REPLACE FUNCTION public.update_own_cleaner_location(p_lat double precision, p_lng double precision, p_max_distance_meters integer DEFAULT NULL::integer)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_user_id uuid := auth.uid();
  v_geom    geometry(Point, 4326);
  v_geog    geography(Point, 4326);
  v_now     timestamptz := now();
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'Not authorized';
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM public.user_roles ur
    WHERE ur.user_id = v_user_id AND ur.role_id = 'cleaner'
  ) THEN
    RAISE EXCEPTION 'forbidden' USING ERRCODE = '42501';
  END IF;

  v_geom := ST_SetSRID(ST_MakePoint(p_lng, p_lat), 4326);
  v_geog := v_geom::geography;

  -- cleaner_data row may not yet exist for the very newest cleaners
  -- (approval RPC always creates one, but defence in depth).
  INSERT INTO public.cleaner_data (user_id, base_location, max_travel_distance_meters, updated_at)
  VALUES (
    v_user_id,
    v_geom,
    COALESCE(p_max_distance_meters, 30000),
    v_now
  )
  ON CONFLICT (user_id) DO UPDATE SET
    base_location              = EXCLUDED.base_location,
    max_travel_distance_meters = COALESCE(EXCLUDED.max_travel_distance_meters, public.cleaner_data.max_travel_distance_meters),
    updated_at                 = v_now;

  -- profiles row exists for every signed-in user (created by trigger).
  UPDATE public.profiles
  SET location_wkt = v_geog,
      updated_at   = v_now
  WHERE id = v_user_id;

  RETURN jsonb_build_object(
    'user_id',                    v_user_id,
    'latitude',                   p_lat,
    'longitude',                  p_lng,
    'max_travel_distance_meters', COALESCE(p_max_distance_meters, 30000)
  );
END;
$function$


